export enum Priority {
  P1 = 1, // Critical
  P2 = 2, // High
  P3 = 3, // Medium
  P4 = 4  // Low
}

export type ItemType = 'TASK' | 'NOTE' | 'HABIT';
export type HabitFrequency = 'daily' | 'weekly' | 'monthly';

export interface FlowItem {
  id: string;
  type: ItemType;
  content: string;
  description?: string; // Additional context or AI summary

  // Task specific
  isCompleted?: boolean;
  priority?: Priority;
  dueDate?: string; // ISO Date string
  projectId?: string; // Linked Project ID

  // Habit specific
  streak?: number;
  lastCompletedDate?: string; // YYYY-MM-DD
  frequency?: HabitFrequency;

  // Metadata
  tags?: string[];
  createdAt: string;
  mood?: 'neutral' | 'positive' | 'negative' | 'focused' | 'anxious'; // AI inferred mood
}

// Added for components/AddTask.tsx
export interface Project {
  id: string;
  name: string;
  color: string;
}

export interface ParsedTask {
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  projectName?: string;
}

// Added for components/TaskItem.tsx
export type Task = FlowItem;

export interface ViewState {
  type: 'HABITS' | 'TODO_TODAY' | 'JOURNAL' | 'PROJECT' | 'TAG';
  id?: string; // projectId or tagName (for filtering)
}

// Gemini Parsing Result
export interface ProcessedInput {
  items: Array<{
    type: ItemType;
    content: string;
    description?: string;
    priority?: number;
    dueDate?: string;
    mood?: string;
    streak?: number;
    frequency?: HabitFrequency;
    tags?: string[];
  }>;
  summary?: string; // A quick reflection on what was said
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessedInput, Priority, ParsedTask } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to convert Blob to Base64
export const blobToBase64 = (blob: Blob): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove data url prefix (e.g. "data:audio/webm;base64,")
      const base64 = base64String.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
};

export const processVoiceEntry = async (audioBase64: string): Promise<ProcessedInput | null> => {
  const now = new Date().toLocaleString();

  const prompt = `
    You are EchoFlow, a cognitive offload assistant.
    The user has just recorded a voice note.
    Analyze the audio and extract actionable items, habits, or personal reflections.

    Current context: ${now}

    Rules:
    1. If the user mentions something to do, create a TASK. Infer priority (1=Urgent, 4=Low).
    2. If the user talks about feelings, ideas, or events, create a NOTE. Infer their mood.
    3. If the user mentions a recurring behavior to track, create a HABIT. Determine frequency: "daily", "weekly", or "monthly". Default to "daily".
    4. If the user mentions a current streak (e.g. "5 days in a row"), extract it as 'streak'.
    5. Clean up the text content to be concise. Put extra details in description.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash-exp",
      contents: {
        parts: [
            { inlineData: { mimeType: "audio/webm", data: audioBase64 } },
            { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
                  content: { type: Type.STRING },
                  description: { type: Type.STRING },
                  priority: { type: Type.INTEGER },
                  dueDate: { type: Type.STRING },
                  mood: { type: Type.STRING },
                  streak: { type: Type.INTEGER },
                  frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
                  tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["type", "content"]
              }
            },
            summary: { type: Type.STRING }
          }
        }
      }
    });

    const text = response.text;
    return text ? JSON.parse(text) : null;
  } catch (error) {
    console.error("EchoFlow AI Processing Error:", error);
    return null;
  }
};

export const processTextEntry = async (textInput: string): Promise<ProcessedInput | null> => {
    // Similar to voice, but for text input
    const now = new Date().toLocaleString();
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.0-flash-exp",
            contents: `Analyze this input for EchoFlow: "${textInput}". Current time: ${now}. Classify into tasks, notes, or habits. For habits, detect frequency (daily, weekly, monthly).`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
                                    content: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    priority: { type: Type.INTEGER },
                                    dueDate: { type: Type.STRING },
                                    mood: { type: Type.STRING },
                                    streak: { type: Type.INTEGER },
                                    frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
                                    tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                                },
                                required: ["type", "content"]
                            }
                        }
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : null;
    } catch (e) {
        return null;
    }
}

export const parseTaskWithGemini = async (rawInput: string, projectNames: string[]): Promise<ParsedTask | null> => {
  const now = new Date().toISOString();
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash-exp",
      contents: `
        You are a smart task parser.
        Current Time: ${now}
        Projects: ${JSON.stringify(projectNames)}

        Input: "${rawInput}"

        Extract:
        - content: clear task title
        - description: extra details
        - priority: 1 (Urgent) to 4 (Low). Default 4.
        - dueDate: YYYY-MM-DD
        - projectName: Exact match from provided list if applicable
      `,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            content: { type: Type.STRING },
            description: { type: Type.STRING },
            priority: { type: Type.INTEGER },
            dueDate: { type: Type.STRING },
            projectName: { type: Type.STRING }
          },
          required: ["content"]
        }
      }
    });

    return response.text ? JSON.parse(response.text) : null;
  } catch (error) {
    console.error("Task parsing error", error);
    return null;
  }
};

export const suggestSubtasks = async (taskContent: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash-exp",
      contents: `List 3-5 subtasks for: "${taskContent}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    return response.text ? JSON.parse(response.text) : [];
  } catch (error) {
    console.error("Subtask suggestion error", error);
    return [];
  }
};

import React from 'react';
import { 
  Waves, 
  Sun, 
  Repeat,
  BookHeart, 
  Hash,
  Plus
} from 'lucide-react';
import { ViewState, Project } from '../types';

interface SidebarProps {
  currentView: ViewState;
  projects: Project[];
  onViewChange: (view: ViewState) => void;
  onAddProject: () => void;
  isMobileOpen: boolean;
  onCloseMobile: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  currentView, 
  projects,
  onViewChange, 
  onAddProject,
  isMobileOpen,
  onCloseMobile
}) => {
  const navItemClass = (isActive: boolean) => `
    flex items-center gap-3 px-3 py-2 rounded-lg cursor-pointer text-sm font-medium transition-all duration-200 select-none
    ${isActive 
      ? 'bg-indigo-50 text-indigo-700' 
      : 'text-gray-600 hover:bg-gray-100 hover:text-gray-900'}
  `;

  return (
    <>
      {/* Mobile Overlay */}
      {isMobileOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/20 backdrop-blur-sm z-30 md:hidden"
          onClick={onCloseMobile}
        />
      )}

      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-slate-50 border-r border-slate-200 transform transition-transform duration-300 ease-out flex flex-col
        ${isMobileOpen ? 'translate-x-0 shadow-2xl' : '-translate-x-full'}
        md:translate-x-0 md:static md:h-screen md:shadow-none
      `}>
        <div className="p-4 flex-1 overflow-y-auto scrollbar-hide">
          {/* Header */}
          <div className="flex items-center gap-2 mb-6 px-2 pt-2">
            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white shadow-sm">
               <Waves size={18} />
            </div>
            <span className="font-serif font-semibold text-xl text-slate-900 tracking-tight">EchoFlow</span>
          </div>

          {/* Main Nav */}
          <nav className="space-y-1 mb-8">
            <div 
              className={navItemClass(currentView.type === 'HABITS')}
              onClick={() => { onViewChange({ type: 'HABITS' }); onCloseMobile(); }}
            >
              <Repeat size={18} />
              Habits
            </div>
            <div 
              className={navItemClass(currentView.type === 'TODO_TODAY')}
              onClick={() => { onViewChange({ type: 'TODO_TODAY' }); onCloseMobile(); }}
            >
              <Sun size={18} />
              Todo Today
            </div>
            <div 
              className={navItemClass(currentView.type === 'JOURNAL')}
              onClick={() => { onViewChange({ type: 'JOURNAL' }); onCloseMobile(); }}
            >
              <BookHeart size={18} />
              Reflections
            </div>
          </nav>

          {/* Projects Header */}
          <div className="flex items-center justify-between px-3 mb-2 group">
            <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Projects</h3>
            <button 
                onClick={onAddProject}
                className="text-gray-400 hover:text-indigo-600 transition-colors p-1 rounded hover:bg-gray-200"
            >
                <Plus size={14} />
            </button>
          </div>

          {/* Projects List */}
          <nav className="space-y-0.5">
            {projects.map(project => (
                <div 
                    key={project.id}
                    className={navItemClass(currentView.type === 'PROJECT' && currentView.id === project.id)}
                    onClick={() => { onViewChange({ type: 'PROJECT', id: project.id }); onCloseMobile(); }}
                >
                    <span style={{ color: project.color }} className="flex-shrink-0">
                        <Hash size={16} />
                    </span>
                    <span className="truncate">{project.name}</span>
                </div>
            ))}

            {projects.length === 0 && (
                <div className="px-3 py-4 text-xs text-gray-400 italic text-center">
                    No projects yet.
                </div>
            )}
          </nav>
        </div>

        <div className="p-4 border-t border-slate-200">
             <div className="text-xs text-slate-400 flex flex-col gap-1">
                <p>Synced • Gemini 2.0 Flash</p>
             </div>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu, Tag } from 'lucide-react';
import Sidebar from './components/Sidebar';
import VoiceCapture from './components/VoiceCapture';
import FlowItem from './components/FlowItem';
import AddTask from './components/AddTask';
import ProjectModal from './components/ProjectModal';
import { FlowItem as FlowItemType, ViewState, ProcessedInput, Priority, Project, HabitFrequency } from './types';

const INITIAL_PROJECTS: Project[] = [
    { id: 'p-home', name: 'Home', color: '#16a34a' },
    { id: 'p-work', name: 'Work', color: '#2563eb' }
];

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'NOTE',
    content: 'Welcome to EchoFlow. Your mind is for having ideas, not holding them.',
    description: 'Tap the microphone below to start dumping your thoughts. I will organize them for you.',
    createdAt: new Date().toISOString(),
    mood: 'focused',
    projectId: 'p-home',
    tags: ['welcome']
  },
  {
    id: 'welcome-2',
    type: 'TASK',
    content: 'Try adding a task with a tag like #urgent or assigning it to a project.',
    priority: Priority.P3,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'p-work',
    tags: ['tutorial']
  },
  {
      id: 'habit-1',
      type: 'HABIT',
      content: 'Drink 2L Water',
      streak: 3,
      frequency: 'daily',
      createdAt: new Date().toISOString()
  },
  {
      id: 'habit-2',
      type: 'HABIT',
      content: 'Weekly Review',
      streak: 1,
      frequency: 'weekly',
      createdAt: new Date().toISOString()
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('echoflow_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'HABITS' });
  const [habitTab, setHabitTab] = useState<HabitFrequency>('daily');
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
    localStorage.setItem('echoflow_projects', JSON.stringify(projects));
  }, [items, projects]);

  // Derived state: unique tags from all items
  const allTags = useMemo(() => {
    const tags = new Set<string>();
    items.forEach(item => item.tags?.forEach(tag => tags.add(tag)));
    return Array.from(tags).sort();
  }, [items]);

  const handleProcessedInput = (result: ProcessedInput) => {
    const newItems: FlowItemType[] = result.items.map(item => ({
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      type: item.type,
      content: item.content,
      description: item.description,
      priority: item.priority as Priority,
      dueDate: item.dueDate,
      mood: item.mood as any,
      tags: item.tags,
      streak: item.streak,
      frequency: item.frequency || 'daily', // Default to daily if not parsed
      isCompleted: false,
      projectId: undefined 
    }));

    setItems(prev => [...newItems, ...prev]);
  };

  const handleAddTask = (taskData: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => {
    const newTask: FlowItemType = {
        id: uuidv4(),
        type: 'TASK',
        content: taskData.content,
        description: taskData.description,
        priority: taskData.priority,
        projectId: taskData.projectId === 'inbox' ? undefined : taskData.projectId,
        dueDate: taskData.dueDate,
        createdAt: new Date().toISOString(),
        isCompleted: false,
        tags: [] 
    };
    setItems(prev => [newTask, ...prev]);
    setShowAddTask(false);
  };

  const handleAddProject = (name: string, color: string) => {
    const newProject = { id: uuidv4(), name, color };
    setProjects(prev => [...prev, newProject]);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id !== id) return item;

      // Handle Habit Check-in
      if (item.type === 'HABIT') {
        const d = new Date();
        const today = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
        const isDoneToday = item.lastCompletedDate === today;

        if (isDoneToday) {
          // Undo check-in
          return {
            ...item,
            streak: Math.max(0, (item.streak || 0) - 1),
            lastCompletedDate: undefined
          };
        } else {
          // Check-in
          return {
            ...item,
            streak: (item.streak || 0) + 1,
            lastCompletedDate: today
          };
        }
      }

      // Handle Task Toggle
      return { ...item, isCompleted: !item.isCompleted };
    }));
  };

  const handleDelete = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const filteredItems = useMemo(() => {
    let baseItems = items;
    const today = new Date().toISOString().split('T')[0];

    // First filter by View Type
    if (viewState.type === 'TODO_TODAY') {
        // Show tasks that are due today or overdue, OR tasks with no date (to treat as immediate backlog)
        // Todoist "Today" is strictly items with date = today/overdue.
        // But since we removed Inbox, we'll show undated tasks here or just today.
        // Let's match Todoist "Today" strictly (due <= today) + Undated items to prevent data hiding
        baseItems = baseItems.filter(i => 
            i.type === 'TASK' && 
            !i.isCompleted && 
            (!i.dueDate || i.dueDate <= today)
        );
    } else if (viewState.type === 'HABITS') {
        baseItems = baseItems.filter(i => i.type === 'HABIT' && (i.frequency || 'daily') === habitTab);
    } else if (viewState.type === 'JOURNAL') {
        baseItems = baseItems.filter(i => i.type === 'NOTE');
    } else if (viewState.type === 'PROJECT') {
        baseItems = baseItems.filter(i => i.projectId === viewState.id && !i.isCompleted);
    } else if (viewState.type === 'TAG') {
        baseItems = baseItems.filter(i => i.tags?.includes(viewState.id || '') && !i.isCompleted);
    } else {
        // Fallback
        baseItems = baseItems.filter(i => !i.isCompleted);
    }

    return baseItems;
  }, [items, viewState, habitTab]);

  const getPageTitle = () => {
      switch (viewState.type) {
          case 'HABITS': return 'Habits';
          case 'TODO_TODAY': return 'Todo Today';
          case 'JOURNAL': return 'Reflections';
          case 'PROJECT': return projects.find(p => p.id === viewState.id)?.name || 'Project';
          case 'TAG': return `# ${viewState.id}`;
          default: return 'EchoFlow';
      }
  };

  // Shortcut to open Add Task
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if (e.key === 'q' && !showAddTask) {
              e.preventDefault();
              setShowAddTask(true);
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showAddTask]);

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden">
      <Sidebar 
        currentView={viewState}
        projects={projects}
        onViewChange={setViewState}
        onAddProject={() => setIsProjectModalOpen(true)}
        isMobileOpen={isMobileOpen}
        onCloseMobile={() => setIsMobileOpen(false)}
      />

      <main className="flex-1 flex flex-col relative w-full h-full">
        {/* Minimal Header */}
        <header className="h-14 flex items-center justify-between px-6 bg-slate-50/80 backdrop-blur-sm z-10 border-b border-slate-100">
          <button 
            onClick={() => setIsMobileOpen(true)}
            className="md:hidden p-2 -ml-2 text-slate-600 hover:bg-slate-200 rounded-lg transition-colors"
          >
            <Menu size={20} />
          </button>

          <div className="flex-1 flex justify-center md:justify-end">
             {/* Tag Filters - Horizontal Scroll */}
             {allTags.length > 0 && (
                 <div className="flex gap-2 overflow-x-auto scrollbar-hide max-w-[200px] md:max-w-md px-2">
                     {allTags.map(tag => (
                         <button
                            key={tag}
                            onClick={() => setViewState({ type: 'TAG', id: tag })}
                            className={`
                                flex-shrink-0 text-xs px-2 py-1 rounded-full border transition-colors
                                ${viewState.type === 'TAG' && viewState.id === tag 
                                    ? 'bg-indigo-100 text-indigo-700 border-indigo-200' 
                                    : 'bg-white text-slate-500 border-slate-200 hover:border-slate-300'}
                            `}
                         >
                             #{tag}
                         </button>
                     ))}
                     {viewState.type === 'TAG' && (
                         <button 
                            onClick={() => setViewState({ type: 'HABITS' })} // Default back to Habits
                            className="flex-shrink-0 text-xs px-2 py-1 rounded-full bg-gray-200 text-gray-600 hover:bg-gray-300"
                         >
                             Clear
                         </button>
                     )}
                 </div>
             )}
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto pb-40 scrollbar-hide">
          <div className="max-w-3xl mx-auto px-6 md:px-8 pt-8">

            {/* Dynamic Title */}
            <div className="mb-6">
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="font-bold text-2xl text-slate-800 mb-1">
                            {getPageTitle()}
                        </h1>
                        <p className="text-sm text-slate-500">
                            {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}
                        </p>
                    </div>
                </div>

                {/* Habit Tabs */}
                {viewState.type === 'HABITS' && (
                    <div className="flex gap-4 mt-6 border-b border-slate-200">
                        {(['daily', 'weekly', 'monthly'] as HabitFrequency[]).map(tab => (
                            <button
                                key={tab}
                                onClick={() => setHabitTab(tab)}
                                className={`pb-2 text-sm font-medium capitalize transition-colors relative ${
                                    habitTab === tab 
                                    ? 'text-indigo-600' 
                                    : 'text-slate-500 hover:text-slate-700'
                                }`}
                            >
                                {tab}
                                {habitTab === tab && (
                                    <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-indigo-600 rounded-t-full" />
                                )}
                            </button>
                        ))}
                    </div>
                )}
            </div>

            {/* Add Task Component (Inline) */}
            {showAddTask ? (
                <AddTask 
                    projects={projects}
                    defaultProjectId={viewState.type === 'PROJECT' && viewState.id ? viewState.id : 'inbox'}
                    onAddTask={handleAddTask}
                    onCancel={() => setShowAddTask(false)}
                />
            ) : (
                <button 
                    onClick={() => setShowAddTask(true)}
                    className="flex items-center gap-2 text-slate-500 hover:text-red-600 font-medium text-sm mb-6 transition-colors group"
                >
                    <span className="flex items-center justify-center w-6 h-6 rounded-full text-red-600 bg-red-50 group-hover:bg-red-600 group-hover:text-white transition-colors">
                        <span className="text-lg leading-none mb-0.5">+</span>
                    </span>
                    Add task
                </button>
            )}

            {/* Feed */}
            <div className="space-y-1">
              {filteredItems.map(item => (
                <FlowItem 
                  key={item.id} 
                  item={item} 
                  onComplete={handleComplete}
                  onDelete={handleDelete}
                />
              ))}

              {filteredItems.length === 0 && !showAddTask && (
                <div className="flex flex-col items-center justify-center py-20 opacity-40">
                    <div className="w-16 h-1 bg-slate-200 rounded-full mb-4"></div>
                    <p className="text-sm">No {viewState.type === 'HABITS' ? `${habitTab} habits` : 'items'} found.</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Voice Capture Overlay */}
        <VoiceCapture onProcessed={handleProcessedInput} />

        {/* Project Modal */}
        <ProjectModal 
            isOpen={isProjectModalOpen} 
            onClose={() => setIsProjectModalOpen(false)}
            onAdd={handleAddProject}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Check, Clock, MoreHorizontal, StickyNote, Activity, Calendar, Flame, CheckCircle, Circle, Trash2, Tag, Repeat } from 'lucide-react';
import { FlowItem as FlowItemType, Priority } from '../types';

interface FlowItemProps {
  item: FlowItemType;
  onComplete?: (id: string) => void;
  onDelete: (id: string) => void;
}

const FlowItem: React.FC<FlowItemProps> = ({ item, onComplete, onDelete }) => {
  const [showMenu, setShowMenu] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  const isTask = item.type === 'TASK';
  const isHabit = item.type === 'HABIT';

  // Close menu when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const moodColor = {
      'positive': 'bg-emerald-50 text-emerald-700 border-emerald-100',
      'negative': 'bg-rose-50 text-rose-700 border-rose-100',
      'focused': 'bg-indigo-50 text-indigo-700 border-indigo-100',
      'anxious': 'bg-amber-50 text-amber-700 border-amber-100',
      'neutral': 'bg-slate-50 text-slate-600 border-slate-100'
  };

  const priorityColor = {
      [Priority.P1]: 'text-rose-600 bg-rose-50 border-rose-100',
      [Priority.P2]: 'text-amber-600 bg-amber-50 border-amber-100',
      [Priority.P3]: 'text-blue-600 bg-blue-50 border-blue-100',
      [Priority.P4]: 'text-slate-500 bg-slate-50 border-slate-100',
  };

  // Check if habit is done today
  const d = new Date();
  const today = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
  const isDoneToday = item.lastCompletedDate === today;

  const MenuDropdown = () => (
      <div 
        ref={menuRef}
        className="absolute right-0 top-8 w-32 bg-white rounded-lg shadow-xl border border-slate-100 py-1 z-20 animate-in fade-in zoom-in-95 duration-100 origin-top-right"
      >
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onDelete(item.id);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-rose-600 hover:bg-rose-50 flex items-center gap-2"
        >
            <Trash2 size={14} />
            Delete
        </button>
      </div>
  );

  const TagsDisplay = () => (
      item.tags && item.tags.length > 0 ? (
        <div className="flex gap-1 flex-wrap mt-2">
            {item.tags.map(tag => (
                <span key={tag} className="inline-flex items-center gap-0.5 text-[10px] text-slate-400 bg-slate-100 px-1.5 py-0.5 rounded">
                    <Tag size={10} />
                    {tag}
                </span>
            ))}
        </div>
      ) : null
  );

  if (isTask) {
    return (
      <div className="group relative flex items-start gap-4 p-4 bg-white rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-all duration-200 mb-3">
        <button
          onClick={() => onComplete && onComplete(item.id)}
          className={`
            flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-200 mt-0.5
            ${item.isCompleted 
                ? 'bg-slate-200 border-slate-200 text-white' 
                : 'border-slate-300 hover:border-indigo-500 text-transparent'
            }
          `}
        >
          <Check size={14} strokeWidth={3} />
        </button>

        <div className="flex-1 min-w-0">
           <div className="flex items-start justify-between">
                <p className={`text-base font-medium transition-colors ${item.isCompleted ? 'text-slate-400 line-through' : 'text-slate-800'}`}>
                    {item.content}
                </p>
           </div>

           {item.description && (
               <p className="mt-1 text-sm text-slate-500">{item.description}</p>
           )}

           <TagsDisplay />

           <div className="flex items-center gap-2 mt-3">
               {item.priority && item.priority < 4 && (
                   <span className={`px-2 py-0.5 rounded text-[10px] font-bold tracking-wide uppercase border ${priorityColor[item.priority]}`}>
                       {item.priority === 1 ? 'Urgent' : item.priority === 2 ? 'High' : 'Medium'}
                   </span>
               )}
               {item.dueDate && (
                   <span className="flex items-center gap-1 text-xs text-slate-400">
                       <Calendar size={12} />
                       {item.dueDate}
                   </span>
               )}
           </div>
        </div>

        <div className="relative">
            <button 
                onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                className="opacity-0 group-hover:opacity-100 p-2 text-slate-300 hover:text-indigo-500 transition-all rounded hover:bg-slate-50"
            >
                <MoreHorizontal size={16} />
            </button>
            {showMenu && <MenuDropdown />}
        </div>
      </div>
    );
  }

  // Note / Reflection / Habit
  return (
    <div className={`
        group relative p-5 rounded-2xl shadow-sm border mb-3 transition-all duration-200 hover:shadow-md
        ${item.mood ? moodColor[item.mood as keyof typeof moodColor] || moodColor.neutral : 'bg-white border-slate-100'}
    `}>
        <div className="flex items-center justify-between mb-2">
             <div className="flex items-center gap-2 text-xs font-semibold opacity-60 uppercase tracking-wider">
                {isHabit ? <Activity size={14} /> : <StickyNote size={14} />}
                <span>{isHabit ? 'Habit' : 'Reflection'}</span>
                {item.mood && <span>• {item.mood}</span>}
                {item.frequency && isHabit && (
                    <span className="flex items-center gap-1 ml-1 bg-black/5 px-1.5 py-0.5 rounded text-[10px]">
                        <Repeat size={10} />
                        {item.frequency}
                    </span>
                )}
            </div>
             <div className="relative">
                <button 
                    onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                    className="opacity-0 group-hover:opacity-100 p-1.5 -mr-2 text-black/20 hover:text-black/60 transition-all rounded hover:bg-black/5"
                >
                    <MoreHorizontal size={16} />
                </button>
                {showMenu && <MenuDropdown />}
            </div>
        </div>

        <div className="font-serif text-lg text-slate-800 leading-relaxed">
            {item.content}
        </div>

        {item.description && (
            <div className="mt-3 pt-3 border-t border-black/5 text-sm opacity-80">
                {item.description}
            </div>
        )}

        <TagsDisplay />

        {isHabit && (
            <div className="mt-4 pt-3 border-t border-black/5 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-1.5 px-2.5 py-1 bg-gradient-to-br from-orange-50 to-amber-50 rounded-lg text-xs font-semibold text-orange-700 border border-orange-100/50 shadow-sm">
                        <Flame size={12} className={item.streak && item.streak > 0 ? "fill-orange-500 text-orange-500" : "text-orange-300"} />
                        <span>{item.streak || 0} Streak</span>
                    </div>

                    {/* Progress dots - Simple visualization */}
                    <div className="flex gap-1 opacity-40">
                        {[...Array(5)].map((_, i) => (
                            <div key={i} className={`w-1.5 h-1.5 rounded-full ${i < ((item.streak || 0) % 5) || (item.streak && item.streak >= 5 && i===4) ? 'bg-orange-500' : 'bg-slate-300'}`} />
                        ))}
                    </div>
                </div>

                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    onComplete && onComplete(item.id);
                  }}
                  className={`
                    flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-semibold transition-all shadow-sm
                    ${isDoneToday 
                        ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' 
                        : 'bg-white text-slate-500 border border-slate-200 hover:border-indigo-200 hover:text-indigo-600'}
                  `}
                >
                    {isDoneToday ? <CheckCircle size={14} /> : <Circle size={14} />}
                    {isDoneToday ? 'Done today' : 'Check in'}
                </button>
            </div>
        )}
    </div>
  );
};

export default FlowItem;

