  const menuRef = useRef<HTMLDivElement>(null);

  const isTask = item.type === 'TASK';
  const isHabit = item.type === 'HABIT';

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Priority styles for the circle border/fill
  const priorityStyle = {
      [Priority.P1]: 'border-[#d1453b] bg-[#fdf2f2] text-[#d1453b]',
      [Priority.P2]: 'border-[#eb8909] bg-[#fff8e6] text-[#eb8909]',
      [Priority.P3]: 'border-[#246fe0] bg-[#e6f0ff] text-[#246fe0]',
      [Priority.P4]: 'border-gray-400 hover:border-gray-500 text-gray-500',
  };

  const getPriorityColor = (p?: Priority) => {
      switch(p) {
          case Priority.P1: return '#d1453b';
          case Priority.P2: return '#eb8909';
          case Priority.P3: return '#246fe0';
          default: return 'gray';
      }
  };

  const MenuDropdown = () => (
      <div 
