        className="absolute right-0 top-8 w-40 bg-white rounded shadow-[0_4px_12px_rgba(0,0,0,0.1)] border border-gray-100 py-1 z-20"
      >
        <button 
            onClick={(e) => {
                e.stopPropagation();
                // Edit logic would go here
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-[13px] text-gray-700 hover:bg-gray-100 flex items-center gap-2"
        >
            <Edit2 size={14} />
            Edit task
        </button>
        <div className="h-px bg-gray-100 my-1" />
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onDelete(item.id);
                setShowMenu(false);
            }}
