                        {tag}
                   </div>
               ))}
           </div>
        </div>

        {/* Actions (Hidden until hover) */}
        <div className="relative opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                className="p-1 text-gray-400 hover:text-gray-800 rounded hover:bg-gray-200"
            >
                <MoreHorizontal size={16} />
            </button>
            {showMenu && <MenuDropdown />}
        </div>
    </div>
  );
};

export default FlowItem;

import React, { useState, useRef, useEffect } from 'react';
import { Calendar, Flag, Hash, Sparkles, X } from 'lucide-react';
import { Priority, Project } from '../types';
import { parseTaskWithGemini } from '../services/geminiService';

interface AddTaskProps {
  projects: Project[];
  defaultProjectId: string;
  onAddTask: (task: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => void;
  onCancel: () => void;
}

const AddTask: React.FC<AddTaskProps> = ({ projects, defaultProjectId, onAddTask, onCancel }) => {
  const [content, setContent] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<Priority>(Priority.P4);
  const [projectId, setProjectId] = useState<string>(defaultProjectId);
  const [dueDate, setDueDate] = useState<string>('');

  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!content.trim()) return;

    onAddTask({
      content,
      description: description.trim() || undefined,
      priority,
      projectId,
      dueDate: dueDate || undefined
    });
    setContent('');
    setDescription('');
  };

  const handleAiParse = async () => {
    if (!content.trim()) return;
    setIsAiProcessing(true);

    // Combine content and description for context
    const fullText = `${content} ${description}`;
    const projectNames = projects.map(p => p.name);

    const parsed = await parseTaskWithGemini(fullText, projectNames);

    if (parsed) {
      setContent(parsed.content);
      if (parsed.description) setDescription(parsed.description);
      if (parsed.priority) setPriority(parsed.priority);
      if (parsed.dueDate) setDueDate(parsed.dueDate);

      if (parsed.projectName) {
        const matchedProject = projects.find(p => p.name.toLowerCase() === parsed.projectName?.toLowerCase());
        if (matchedProject) setProjectId(matchedProject.id);
      }
    }
    setIsAiProcessing(false);
  };

  const priorityColors = {
    [Priority.P1]: 'text-[#d1453b]',
    [Priority.P2]: 'text-[#eb8909]',
    [Priority.P3]: 'text-[#246fe0]',
    [Priority.P4]: 'text-gray-500',
  };

  return (
    <div className="border border-gray-200 rounded-[10px] p-3 bg-white shadow-sm mb-4">
      <form onSubmit={handleSubmit}>
        <div className="mb-2">
          <input
            ref={inputRef}
            type="text"
            placeholder="Task name"
            className="w-full text-[14px] font-medium text-[#202020] placeholder:text-gray-400 focus:outline-none bg-transparent mb-1"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            disabled={isAiProcessing}
          />
          <textarea
            placeholder="Description"
            rows={1}
            className="w-full text-[13px] text-gray-600 placeholder:text-gray-400 focus:outline-none resize-none bg-transparent"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            disabled={isAiProcessing}
          />
        </div>

        <div className="flex items-center gap-2 mb-3">
            {/* Due Date */}
            <button 
                type="button" 
                className={`flex items-center gap-1 px-2 py-1 rounded border border-gray-200 text-xs text-gray-500 hover:bg-gray-50 transition-colors ${dueDate ? 'text-[#058527] bg-green-50 border-green-200' : ''}`}
                onClick={() => {
                    const tomorrow = new Date();
                    tomorrow.setDate(tomorrow.getDate() + 1);
                    setDueDate(dueDate ? '' : tomorrow.toISOString().split('T')[0]);
                }}
            >
              <Calendar size={14} />
              {dueDate ? 'Tomorrow' : 'Due date'}
            </button>

            {/* Priority */}
            <div className="relative group">
                <button type="button" className={`flex items-center gap-1 px-2 py-1 rounded border border-gray-200 text-xs hover:bg-gray-50 transition-colors ${priority !== Priority.P4 ? priorityColors[priority] : 'text-gray-500'}`}>
                    <Flag size={14} fill={priority === Priority.P4 ? 'none' : 'currentColor'} />
                    Priority
                </button>
                <div className="absolute top-full left-0 mt-1 w-28 bg-white border border-gray-200 rounded shadow-lg hidden group-hover:block z-10 py-1">
                    {[Priority.P1, Priority.P2, Priority.P3, Priority.P4].map(p => (
                        <div key={p} onClick={() => setPriority(p)} className="flex items-center gap-2 px-3 py-1.5 hover:bg-gray-100 cursor-pointer text-xs text-gray-700">
                             <Flag size={14} className={priorityColors[p]} fill={p === Priority.P4 ? 'none' : 'currentColor'}/> 
                             Priority {p}
                        </div>
                    ))}
                </div>
            </div>
        </div>

        <div className="flex items-center justify-between border-t border-gray-100 pt-3">
            <div className="relative group">
                <button type="button" className="flex items-center gap-1.5 px-2 py-1.5 rounded hover:bg-gray-100 text-xs text-gray-600 font-medium transition-colors">
                    <Hash size={14} />
                    {projects.find(p => p.id === projectId)?.name || 'Inbox'}
                </button>
                 <div className="absolute top-full left-0 mt-1 w-40 max-h-40 overflow-y-auto bg-white border border-gray-200 rounded shadow-lg hidden group-hover:block z-10">
                    <div onClick={() => setProjectId('inbox')} className="px-3 py-2 hover:bg-gray-100 cursor-pointer text-xs truncate flex items-center gap-2 text-gray-700">
                        <Hash size={12} /> Inbox
                    </div>
                    {projects.map(p => (
                        <div key={p.id} onClick={() => setProjectId(p.id)} className="px-3 py-2 hover:bg-gray-100 cursor-pointer text-xs truncate flex items-center gap-2 text-gray-700">
                            <span className="w-2 h-2 rounded-full" style={{backgroundColor: p.color}}></span>
                            {p.name}
                        </div>
                    ))}
                </div>
            </div>

          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={onCancel}
              className="px-3 py-1.5 rounded-[5px] text-[13px] font-semibold text-gray-700 hover:bg-gray-100 bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!content.trim() || isAiProcessing}
              className={`px-3 py-1.5 rounded-[5px] text-[13px] font-semibold text-white transition-colors ${!content.trim() ? 'bg-[#ffc2bd] cursor-not-allowed' : 'bg-[#db4c3f] hover:bg-[#b03d32]'}`}
            >
              Add task
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

