import VoiceCapture from './components/VoiceCapture';
import FlowItem from './components/FlowItem';
import AddTask from './components/AddTask';
import ProjectModal from './components/ProjectModal';
import { FlowItem as FlowItemType, ViewState, ProcessedInput, Priority, Project, HabitFrequency } from './types';

const INITIAL_PROJECTS: Project[] = [
    { id: 'p-personal', name: 'Personal', color: '#db4c3f' },
    { id: 'p-work', name: 'Work', color: '#2563eb' }
];

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'TASK',
    content: 'Welcome to EchoFlow',
    description: 'This is your new mental inbox. It looks familiar, but it listens.',
    priority: Priority.P1,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'p-personal',
    tags: ['welcome']
  },
  {
    id: 'welcome-2',
    type: 'TASK',
    content: 'Click the + button to add a task',
    priority: Priority.P4,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'inbox',
  },
  {
      id: 'habit-1',
      type: 'HABIT',
      content: 'Morning Meditation',
      streak: 5,
      frequency: 'daily',
      createdAt: new Date().toISOString()
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('echoflow_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  // Default to INBOX
  const [viewState, setViewState] = useState<ViewState>({ type: 'INBOX' });
  const [habitTab, setHabitTab] = useState<HabitFrequency>('daily');
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
    localStorage.setItem('echoflow_projects', JSON.stringify(projects));
  }, [items, projects]);

  const handleProcessedInput = (result: ProcessedInput) => {
    const newItems: FlowItemType[] = result.items.map(item => ({
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      type: item.type,
      content: item.content,
      description: item.description,
      priority: item.priority as Priority,
      dueDate: item.dueDate,
      mood: item.mood as any,
      tags: item.tags,
      streak: item.streak,
      frequency: item.frequency || 'daily', 
      isCompleted: false,
      projectId: 'inbox' // Default to inbox
    }));

    setItems(prev => [...newItems, ...prev]);
  };

  const handleAddTask = (taskData: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => {
    const newTask: FlowItemType = {
        id: uuidv4(),
        type: 'TASK',
        content: taskData.content,
        description: taskData.description,
        priority: taskData.priority,
        projectId: taskData.projectId === 'inbox' ? 'inbox' : taskData.projectId,
        dueDate: taskData.dueDate,
        createdAt: new Date().toISOString(),
        isCompleted: false,
        tags: [] 
    };
    setItems(prev => [newTask, ...prev]);
    setShowAddTask(false);
  };

  const handleAddProject = (name: string, color: string) => {
    const newProject = { id: uuidv4(), name, color };
    setProjects(prev => [...prev, newProject]);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id !== id) return item;
      if (item.type === 'HABIT') {
        const d = new Date();
        const today = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
        const isDoneToday = item.lastCompletedDate === today;
        return {
            ...item,
            streak: isDoneToday ? Math.max(0, (item.streak || 0) - 1) : (item.streak || 0) + 1,
            lastCompletedDate: isDoneToday ? undefined : today
        };
      }
      return { ...item, isCompleted: !item.isCompleted };
    }));
  };

  const handleDelete = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const filteredItems = useMemo(() => {
    let baseItems = items;
    const today = new Date().toISOString().split('T')[0];

    // Filter Logic
    switch (viewState.type) {
        case 'INBOX':
            // Items with no project or project id 'inbox', and not completed (unless we want to show completed)
            // Todoist Inbox is strictly things without a project.
            baseItems = baseItems.filter(i => (i.projectId === 'inbox' || !i.projectId) && !i.isCompleted);
            break;
        case 'TODAY':
            baseItems = baseItems.filter(i => 
                !i.isCompleted && 
                i.dueDate && i.dueDate <= today
            );
            break;
        case 'UPCOMING':
             baseItems = baseItems.filter(i => 
                !i.isCompleted && 
                i.dueDate && i.dueDate > today
            );
            break;
        case 'HABITS':
            baseItems = baseItems.filter(i => i.type === 'HABIT' && (i.frequency || 'daily') === habitTab);
            break;
        case 'JOURNAL':
            baseItems = baseItems.filter(i => i.type === 'NOTE');
            break;
        case 'PROJECT':
            baseItems = baseItems.filter(i => i.projectId === viewState.id && !i.isCompleted);
            break;
        case 'TAG':
            baseItems = baseItems.filter(i => i.tags?.includes(viewState.id || '') && !i.isCompleted);
            break;
        default:
            baseItems = baseItems.filter(i => !i.isCompleted);
    }
    return baseItems;
  }, [items, viewState, habitTab]);

  const getPageTitle = () => {
      switch (viewState.type) {
          case 'INBOX': return 'Inbox';
          case 'TODAY': return 'Today';
          case 'UPCOMING': return 'Upcoming';
          case 'HABITS': return 'Habits';
          case 'JOURNAL': return 'Journal';
          case 'PROJECT': return projects.find(p => p.id === viewState.id)?.name || 'Project';
          case 'TAG': return `# ${viewState.id}`;
          default: return 'Inbox';
      }
  };

  // Shortcut to open Add Task
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if ((e.key === 'q' || e.key === 'a') && !showAddTask) {
              e.preventDefault();
              setShowAddTask(true);
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showAddTask]);

  return (
    <div className="flex flex-col h-screen bg-white text-[#202020]">
      {/* Todoist-like Red Header */}
      <header className="h-[48px] bg-[#db4c3f] flex items-center justify-between px-3 text-white shrink-0 z-50">
          <div className="flex items-center gap-3">
            <button 
                onClick={() => setIsMobileOpen(!isMobileOpen)}
                className="p-1 hover:bg-white/20 rounded transition-colors"
            >
                <Menu size={24} />
            </button>
            <button 
                onClick={() => setViewState({type: 'INBOX'})}
                className="p-1 hover:bg-white/20 rounded transition-colors"
            >
                <Home size={20} />
            </button>
            <div className="relative ml-2 hidden sm:block">
                <input 
                    type="text" 
                    placeholder="Search" 
                    className="bg-white/20 text-white placeholder-white/70 rounded-[4px] pl-8 pr-2 py-1 text-sm focus:outline-none focus:bg-white focus:text-gray-800 focus:placeholder-gray-400 w-48 transition-all"
                />
                <Search size={16} className="absolute left-2 top-1.5 text-white/70 pointer-events-none" />
            </div>
          </div>

          <div className="flex items-center gap-2">
              <button className="p-1.5 hover:bg-white/20 rounded transition-colors" onClick={() => setShowAddTask(true)}>
                  <Plus size={24} />
              </button>
              <button className="p-1.5 hover:bg-white/20 rounded transition-colors">
                  <Bell size={20} />
              </button>
              <div className="w-7 h-7 bg-white/20 rounded-full flex items-center justify-center text-xs font-semibold">
                  EF
              </div>
          </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <Sidebar 
            currentView={viewState}
            projects={projects}
            onViewChange={setViewState}
            onAddProject={() => setIsProjectModalOpen(true)}
            isMobileOpen={isMobileOpen}
            onCloseMobile={() => setIsMobileOpen(false)}
        />

        <main className="flex-1 flex flex-col relative w-full h-full overflow-hidden bg-white">
            <div className="flex-1 overflow-y-auto scrollbar-hide">
                <div className="max-w-[800px] mx-auto px-4 md:px-12 pt-8 pb-32">

                    {/* View Header */}
                    <div className="mb-4">
                        <h1 className="text-[20px] font-bold text-[#202020] mb-1 flex items-center gap-2">
                            {getPageTitle()}
                            {viewState.type === 'TODAY' && <span className="text-xs font-normal text-gray-500">{new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}</span>}
                        </h1>

                        {/* Habit Tabs */}
                        {viewState.type === 'HABITS' && (
                            <div className="flex gap-4 mt-4 border-b border-slate-200">
                                {(['daily', 'weekly', 'monthly'] as HabitFrequency[]).map(tab => (
                                    <button
                                        key={tab}
                                        onClick={() => setHabitTab(tab)}
                                        className={`pb-2 text-sm font-medium capitalize transition-colors relative ${
                                            habitTab === tab 
                                            ? 'text-[#db4c3f]' 
                                            : 'text-slate-500 hover:text-slate-700'
                                        }`}
                                    >
                                        {tab}
                                        {habitTab === tab && (
                                            <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-[#db4c3f] rounded-t-full" />
                                        )}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Task List */}
                    <div>
                        {filteredItems.map(item => (
                            <FlowItem 
                                key={item.id} 
                                item={item} 
                                onComplete={handleComplete}
                                onDelete={handleDelete}
                            />
                        ))}
                    </div>

                    {/* Inline Add Task Trigger */}
                    {!showAddTask && (
                        <button 
                            onClick={() => setShowAddTask(true)}
                            className="group flex items-center gap-2 mt-4 text-gray-500 hover:text-[#db4c3f] transition-colors text-[14px]"
                        >
                            <div className="w-[18px] h-[18px] rounded-full flex items-center justify-center text-[#db4c3f] group-hover:bg-[#db4c3f] group-hover:text-white transition-colors">
                                <Plus size={14} />
                            </div>
                            <span className="font-normal">Add task</span>
                        </button>
                    )}

                    {/* Add Task Form */}
                    {showAddTask && (
                        <div className="mt-4">
                            <AddTask 
                                projects={projects}
                                defaultProjectId={viewState.type === 'PROJECT' && viewState.id ? viewState.id : 'inbox'}
                                onAddTask={handleAddTask}
                                onCancel={() => setShowAddTask(false)}
                            />
                        </div>
                    )}

                    {filteredItems.length === 0 && !showAddTask && (
                        <div className="flex flex-col items-center justify-center py-16 opacity-50">
                            <div className="text-sm text-gray-400">All clear</div>
                            <div className="text-xs text-gray-300 mt-1">Looks like everything's organized.</div>
                        </div>
                    )}
                </div>
            </div>

            {/* Voice Capture Overlay */}
            <VoiceCapture onProcessed={handleProcessedInput} />

            {/* Project Modal */}
            <ProjectModal 
                isOpen={isProjectModalOpen} 
                onClose={() => setIsProjectModalOpen(false)}
                onAdd={handleAddProject}
            />
        </main>
      </div>
    </div>
  );
};

