            // Items with no project or project id 'inbox', and not completed (unless we want to show completed)
            baseItems = baseItems.filter(i => (i.projectId === 'inbox' || !i.projectId) && !i.isCompleted);
            break;
        case 'TODAY':
            baseItems = baseItems.filter(i => 
                !i.isCompleted && 
                i.dueDate && i.dueDate <= today
            );
            break;
        case 'UPCOMING':
             baseItems = baseItems.filter(i => 
                !i.isCompleted && 
                i.dueDate && i.dueDate > today
            );
            break;
        case 'HABITS':
            baseItems = baseItems.filter(i => i.type === 'HABIT' && (i.frequency || 'daily') === habitTab);
            break;
        case 'JOURNAL':
            baseItems = baseItems.filter(i => i.type === 'NOTE');
            break;
        case 'PROJECT':
            baseItems = baseItems.filter(i => i.projectId === viewState.id && !i.isCompleted);
            break;
        case 'TAG':
            baseItems = baseItems.filter(i => i.tags?.includes(viewState.id || '') && !i.isCompleted);
            break;
        default:
            baseItems = baseItems.filter(i => !i.isCompleted);
    }
    return baseItems;
  }, [items, viewState, habitTab]);

  const getPageTitle = () => {
      switch (viewState.type) {
          case 'INBOX': return 'Inbox';
          case 'TODAY': return 'Today';
          case 'UPCOMING': return 'Upcoming';
          case 'HABITS': return 'Habits';
          case 'JOURNAL': return 'Journal';
          case 'PROJECT': return projects.find(p => p.id === viewState.id)?.name || 'Project';
          case 'TAG': return `# ${viewState.id}`;
          default: return 'Inbox';
      }
  };

  // Shortcut to open Add Task
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if ((e.key === 'q' || e.key === 'a') && !showAddTask) {
              // Only trigger if not typing in an input
              if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;
              e.preventDefault();
              setShowAddTask(true);
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showAddTask]);

  return (
