import React, { useState, useRef } from 'react';
import { Mic, Square, Loader2, SendHorizontal, Keyboard } from 'lucide-react';
import { blobToBase64, processVoiceEntry, processTextEntry } from '../services/geminiService';
import { ProcessedInput } from '../types';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const [textInput, setTextInput] = useState('');

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        setIsProcessing(true);
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/webm' });

        // Stop all tracks to release mic
        stream.getTracks().forEach(track => track.stop());

        try {
          const base64 = await blobToBase64(audioBlob);
          const result = await processVoiceEntry(base64);
          if (result) {
            onProcessed(result);
          }
        } catch (err) {
          console.error("Processing failed", err);
          alert("Could not process audio. Please try again.");
        } finally {
          setIsProcessing(false);
        }
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access is required for voice capture.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!textInput.trim()) return;

    setIsProcessing(true);
    try {
        const result = await processTextEntry(textInput);
        if (result) onProcessed(result);
        setTextInput('');
        setShowTextInput(false);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-[280px] right-0 p-6 flex flex-col items-center justify-end z-20 pointer-events-none transition-all duration-200">
       {/* Text Input Overlay */}
       {showTextInput && (
           <div className="pointer-events-auto w-full max-w-2xl mb-4 bg-white dark:bg-[#282828] rounded-2xl shadow-xl border border-slate-200 dark:border-[#363636] p-2 animate-in slide-in-from-bottom-5">
               <form onSubmit={handleTextSubmit} className="flex gap-2">
                   <input 
                      autoFocus
                      className="flex-1 px-4 py-3 bg-transparent outline-none text-slate-800 dark:text-gray-200 placeholder:text-slate-400"
                      placeholder="Type your thought..."
                      value={textInput}
                      onChange={e => setTextInput(e.target.value)}
                      disabled={isProcessing}
                   />
                   <button 
                      type="submit" 
                      disabled={isProcessing || !textInput.trim()}
                      className="p-3 bg-[#db4c3f] text-white rounded-xl hover:bg-[#b03d32] transition-colors disabled:opacity-50"
                   >
                       {isProcessing ? <Loader2 className="animate-spin" size={20}/> : <SendHorizontal size={20}/>}
                   </button>
               </form>
           </div>
       )}

      <div className="pointer-events-auto flex items-center gap-4">
        {/* Keyboard Toggle */}
        <button 
            onClick={() => setShowTextInput(!showTextInput)}
            className="bg-white dark:bg-[#282828] text-slate-500 dark:text-gray-400 p-3 rounded-full shadow-lg border border-slate-100 dark:border-[#363636] hover:text-[#db4c3f] dark:hover:text-[#db4c3f] transition-colors"
        >
            <Keyboard size={20} />
        </button>

        {/* Main Mic Button */}
        <button
            onClick={isRecording ? stopRecording : startRecording}
            disabled={isProcessing}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-xl transition-all duration-300
            ${isRecording 
                ? 'bg-rose-500 text-white recording-pulse' 
                : isProcessing 
                    ? 'bg-slate-100 dark:bg-[#363636] text-slate-400' 
                    : 'bg-[#db4c3f] text-white hover:bg-[#b03d32] hover:scale-105'
            }
            `}
        >
            {isProcessing ? (
                <Loader2 size={24} className="animate-spin" />
            ) : isRecording ? (
                <Square size={24} fill="currentColor" />
            ) : (
                <Mic size={28} />
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-slate-400 dark:text-gray-500 text-center transition-opacity duration-300">
        {isRecording ? "Listening... Tap to stop" : isProcessing ? "EchoFlow is thinking..." : showTextInput ? "" : "Tap to speak"}
      </div>
    </div>
  );
};

export default VoiceCapture;

export enum Priority {
  P1 = 1, // Critical
  P2 = 2, // High
  P3 = 3, // Medium
  P4 = 4  // Low
}

export type ItemType = 'TASK' | 'NOTE' | 'HABIT';
export type HabitFrequency = 'daily' | 'weekly' | 'monthly';

export interface FlowItem {
  id: string;
  type: ItemType;
  content: string;
  description?: string; // Additional context or AI summary

  // Task specific
  isCompleted?: boolean;
  priority?: Priority;
  dueDate?: string; // ISO Date string
  projectId?: string; // Linked Project ID

  // Habit specific
  streak?: number;
  lastCompletedDate?: string; // YYYY-MM-DD
  frequency?: HabitFrequency;

  // Metadata
  tags?: string[];
  createdAt: string;
  mood?: 'neutral' | 'positive' | 'negative' | 'focused' | 'anxious'; // AI inferred mood
}

// Added for components/AddTask.tsx
export interface Project {
  id: string;
  name: string;
  color: string;
}

export interface ParsedTask {
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  projectName?: string;
}

// Added for components/TaskItem.tsx
export type Task = FlowItem;

export interface ViewState {
  type: 'INBOX' | 'TODAY' | 'UPCOMING' | 'HABITS' | 'JOURNAL' | 'PROJECT' | 'TAG';
  id?: string; // projectId or tagName (for filtering)
}

// Gemini Parsing Result
export interface ProcessedInput {
  items: Array<{
    type: ItemType;
    content: string;
    description?: string;
    priority?: number;
    dueDate?: string;
    mood?: string;
    streak?: number;
    frequency?: HabitFrequency;
    tags?: string[];
  }>;
  summary?: string; // A quick reflection on what was said
}

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu, Plus, Home, Search, Bell, Moon, Sun, X, CheckCircle2, Inbox } from 'lucide-react';
import Sidebar from './components/Sidebar';
import VoiceCapture from './components/VoiceCapture';
import FlowItem from './components/FlowItem';
import AddTask from './components/AddTask';
import ProjectModal from './components/ProjectModal';
import { FlowItem as FlowItemType, ViewState, ProcessedInput, Priority, Project, HabitFrequency } from './types';

const INITIAL_PROJECTS: Project[] = [
    { id: 'p-personal', name: 'Personal', color: '#db4c3f' },
    { id: 'p-work', name: 'Work', color: '#2563eb' }
];

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'TASK',
    content: 'Welcome to EchoFlow',
    description: 'This is your new mental inbox. It looks familiar, but it listens.',
    priority: Priority.P1,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'p-personal',
    tags: ['welcome']
  },
  {
    id: 'welcome-2',
    type: 'TASK',
    content: 'Click the + button to add a task',
    priority: Priority.P4,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'inbox',
  },
  {
      id: 'habit-1',
      type: 'HABIT',
      content: 'Morning Meditation',
      streak: 5,
      frequency: 'daily',
      createdAt: new Date().toISOString()
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('echoflow_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'INBOX' });
  const [habitTab, setHabitTab] = useState<HabitFrequency>('daily');
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [darkMode, setDarkMode] = useState(() => {
      if (typeof window !== 'undefined') {
          return localStorage.getItem('echoflow_theme') === 'dark' || 
                 (!('echoflow_theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
      }
      return false;
  });

  // Toast State
  const [toast, setToast] = useState<{message: string, type: 'success' | 'info'} | null>(null);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
    localStorage.setItem('echoflow_projects', JSON.stringify(projects));
  }, [items, projects]);

  // Dark Mode Effect
  useEffect(() => {
      if (darkMode) {
          document.documentElement.classList.add('dark');
          localStorage.setItem('echoflow_theme', 'dark');
      } else {
          document.documentElement.classList.remove('dark');
          localStorage.setItem('echoflow_theme', 'light');
      }
  }, [darkMode]);

  const showToast = (message: string, type: 'success' | 'info' = 'success') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 3000);
  };

  const handleProcessedInput = (result: ProcessedInput) => {
    const newItems: FlowItemType[] = result.items.map(item => ({
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      type: item.type,
      content: item.content,
      description: item.description,
      priority: item.priority as Priority,
      dueDate: item.dueDate,
      mood: item.mood as any,
      tags: item.tags,
      streak: item.streak,
      frequency: item.frequency || 'daily', 
      isCompleted: false,
      projectId: 'inbox' // Default to inbox
    }));

    setItems(prev => [...newItems, ...prev]);
    showToast(`Added ${newItems.length} item${newItems.length > 1 ? 's' : ''}`);
  };

  const handleAddTask = (taskData: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => {
    const newTask: FlowItemType = {
        id: uuidv4(),
        type: 'TASK',
        content: taskData.content,
        description: taskData.description,
        priority: taskData.priority,
        projectId: taskData.projectId === 'inbox' ? 'inbox' : taskData.projectId,
        dueDate: taskData.dueDate,
        createdAt: new Date().toISOString(),
        isCompleted: false,
        tags: [] 
    };
    setItems(prev => [newTask, ...prev]);
    setShowAddTask(false);
    showToast('Task added');
  };

  const handleUpdateItem = (id: string, updates: Partial<FlowItemType>) => {
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
      showToast('Task updated', 'info');
  };

  const handleAddProject = (name: string, color: string) => {
    const newProject = { id: uuidv4(), name, color };
    setProjects(prev => [...prev, newProject]);
    showToast(`Project "${name}" created`);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id !== id) return item;

      const isCompleting = !item.isCompleted;

      if (item.type === 'HABIT') {
        const d = new Date();
        const today = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
        const isDoneToday = item.lastCompletedDate === today;

        if (!isDoneToday && isCompleting) {
            showToast('Habit streak +1! 🔥');
        }

        return {
            ...item,
            streak: isDoneToday ? Math.max(0, (item.streak || 0) - 1) : (item.streak || 0) + 1,
            lastCompletedDate: isDoneToday ? undefined : today
        };
      }

      if (isCompleting) showToast('Task completed');
      return { ...item, isCompleted: isCompleting };
    }));
  };

  const handleDelete = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
    showToast('Item deleted', 'info');
  };

  const filteredItems = useMemo(() => {
    let baseItems = items;
    const today = new Date().toISOString().split('T')[0];

    // Search Filter
    if (searchQuery.trim()) {
        const q = searchQuery.toLowerCase();
        baseItems = baseItems.filter(i => 
            i.content.toLowerCase().includes(q) || 
            i.description?.toLowerCase().includes(q) ||
            i.tags?.some(t => t.toLowerCase().includes(q))
        );
    }

    // View Logic Filter
    switch (viewState.type) {
        case 'INBOX':
            baseItems = baseItems.filter(i => (i.projectId === 'inbox' || !i.projectId) && !i.isCompleted);
            break;
        case 'TODAY':
            baseItems = baseItems.filter(i => 
                !i.isCompleted && 
                i.dueDate && i.dueDate <= today
            );
            break;
        case 'UPCOMING':
             baseItems = baseItems.filter(i => 
                !i.isCompleted && 
                i.dueDate && i.dueDate > today
            );
            break;
        case 'HABITS':
            baseItems = baseItems.filter(i => i.type === 'HABIT' && (i.frequency || 'daily') === habitTab);
            break;
        case 'JOURNAL':
            baseItems = baseItems.filter(i => i.type === 'NOTE');
            break;
        case 'PROJECT':
            baseItems = baseItems.filter(i => i.projectId === viewState.id && !i.isCompleted);
            break;
        case 'TAG':
            baseItems = baseItems.filter(i => i.tags?.includes(viewState.id || '') && !i.isCompleted);
            break;
        default:
            baseItems = baseItems.filter(i => !i.isCompleted);
    }
    return baseItems;
  }, [items, viewState, habitTab, searchQuery]);

  const getPageTitle = () => {
      if (searchQuery) return 'Search Results';
      switch (viewState.type) {
          case 'INBOX': return 'Inbox';
          case 'TODAY': return 'Today';
          case 'UPCOMING': return 'Upcoming';
          case 'HABITS': return 'Habits';
          case 'JOURNAL': return 'Journal';
          case 'PROJECT': return projects.find(p => p.id === viewState.id)?.name || 'Project';
          case 'TAG': return `# ${viewState.id}`;
          default: return 'Inbox';
      }
  };

  // Shortcut to open Add Task
  useEffect(() => {
      const handleKeyDown = (e: KeyboardEvent) => {
          if ((e.key === 'q' || e.key === 'a') && !showAddTask) {
              if (['INPUT', 'TEXTAREA'].includes((e.target as HTMLElement).tagName)) return;
              e.preventDefault();
              setShowAddTask(true);
          }
          if (e.key === '/' && !searchQuery) {
              e.preventDefault();
              const searchInput = document.getElementById('header-search') as HTMLInputElement;
              searchInput?.focus();
          }
          if (e.key === 'Escape') {
              if (showAddTask) setShowAddTask(false);
              if (searchQuery) setSearchQuery('');
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showAddTask, searchQuery]);

  return (
    <div className="flex flex-col h-screen bg-white dark:bg-[#1f1f1f] text-[#202020] dark:text-gray-200 transition-colors duration-200">
      {/* Header */}
      <header className="h-[48px] bg-[#db4c3f] dark:bg-[#1f1f1f] border-b border-transparent dark:border-[#303030] flex items-center justify-between px-3 text-white dark:text-gray-300 shrink-0 z-50 transition-colors shadow-sm">
          <div className="flex items-center gap-3">
            <button 
                onClick={() => setIsMobileOpen(!isMobileOpen)}
                className="p-1 hover:bg-white/20 dark:hover:bg-white/10 rounded transition-colors md:hidden"
            >
                <Menu size={24} />
            </button>
            <button 
                onClick={() => { setViewState({type: 'INBOX'}); setSearchQuery(''); }}
                className="p-1 hover:bg-white/20 dark:hover:bg-white/10 rounded transition-colors hidden md:block"
            >
                <Home size={20} />
            </button>
            <div className="relative ml-2 w-full max-w-[400px]">
                <input 
