                                        className={`pb-2 text-sm font-medium capitalize transition-colors relative ${
                                            habitTab === tab 
                                            ? 'text-[#db4c3f] dark:text-[#db4c3f]' 
                                            : 'text-slate-500 dark:text-gray-400 hover:text-slate-700 dark:hover:text-gray-200'
