                    {/* Empty State */}
                    {filteredItems.length === 0 && !showAddTask && (
                        <div className="flex flex-col items-center justify-center py-24 opacity-60">
                            <div className="relative mb-4">
                                <Inbox size={64} strokeWidth={1} className="text-gray-300 dark:text-gray-600" />
                                <CheckCircle2 size={24} className="absolute -bottom-1 -right-1 text-green-500 bg-white dark:bg-[#1f1f1f] rounded-full" />
                            </div>
                            <div className="text-[15px] font-medium text-gray-700 dark:text-gray-300">
                                {searchQuery ? 'No results found' : 'All done for now'}
                            </div>
                            <div className="text-[13px] text-gray-400 dark:text-gray-500 mt-1 max-w-xs text-center">
                                {searchQuery 
                                    ? `Could not find anything matching "${searchQuery}"`
                                    : "Enjoy your peace of mind or capture something new below."}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Voice Capture Overlay */}
            <VoiceCapture onProcessed={handleProcessedInput} />

            {/* Project Modal */}
            <ProjectModal 
                isOpen={isProjectModalOpen} 
                onClose={() => setIsProjectModalOpen(false)}
                onAdd={handleAddProject}
            />

            {/* Toast Notification */}
            {toast && (
                <div className="fixed bottom-24 left-1/2 -translate-x-1/2 z-50 animate-in slide-in-from-bottom-5 fade-in duration-300">
                    <div className="bg-gray-900/90 dark:bg-white/90 backdrop-blur text-white dark:text-gray-900 px-4 py-2.5 rounded-lg shadow-lg flex items-center gap-3 text-sm font-medium border border-white/10 dark:border-gray-200/50">
                         {toast.type === 'success' && <CheckCircle2 size={16} className="text-green-400 dark:text-green-600" />}
                         <span>{toast.message}</span>
                         <button onClick={() => setToast(null)} className="ml-2 text-white/60 dark:text-black/40 hover:text-white dark:hover:text-black">
                             <X size={14} />
                         </button>
                    </div>
                </div>
            )}
        </main>
      </div>
    </div>
  );
};

