import React, { useState, useRef, useEffect } from 'react';
import { Calendar, Flag, Hash, Sparkles, X } from 'lucide-react';
import { Priority, Project } from '../types';
import { parseTaskWithGemini } from '../services/geminiService';

interface AddTaskProps {
  projects: Project[];
  defaultProjectId: string;
  onAddTask: (task: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => void;
  onCancel: () => void;
}

const AddTask: React.FC<AddTaskProps> = ({ projects, defaultProjectId, onAddTask, onCancel }) => {
  const [content, setContent] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<Priority>(Priority.P4);
  const [projectId, setProjectId] = useState<string>(defaultProjectId);
  const [dueDate, setDueDate] = useState<string>('');

  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!content.trim()) return;

    onAddTask({
      content,
      description: description.trim() || undefined,
      priority,
      projectId,
      dueDate: dueDate || undefined
    });
    setContent('');
    setDescription('');
  };

  const handleAiParse = async () => {
    if (!content.trim()) return;
    setIsAiProcessing(true);

    // Combine content and description for context
    const fullText = `${content} ${description}`;
    const projectNames = projects.map(p => p.name);

    const parsed = await parseTaskWithGemini(fullText, projectNames);

    if (parsed) {
      setContent(parsed.content);
      if (parsed.description) setDescription(parsed.description);
      if (parsed.priority) setPriority(parsed.priority);
      if (parsed.dueDate) setDueDate(parsed.dueDate);

      if (parsed.projectName) {
        const matchedProject = projects.find(p => p.name.toLowerCase() === parsed.projectName?.toLowerCase());
        if (matchedProject) setProjectId(matchedProject.id);
      }
    }
    setIsAiProcessing(false);
  };

  const priorityColors = {
    [Priority.P1]: 'text-[#d1453b]',
    [Priority.P2]: 'text-[#eb8909]',
    [Priority.P3]: 'text-[#246fe0]',
    [Priority.P4]: 'text-gray-500',
  };

  return (
    <div className="border border-gray-200 dark:border-[#363636] rounded-[10px] p-3 bg-white dark:bg-[#282828] shadow-sm mb-4 transition-colors relative z-10">
      <form onSubmit={handleSubmit}>
        <div className="mb-2">
          <input
            ref={inputRef}
            type="text"
            placeholder="Task name"
            className="w-full text-[14px] font-medium text-[#202020] dark:text-gray-100 placeholder:text-gray-400 dark:placeholder:text-gray-500 focus:outline-none bg-transparent mb-1"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            disabled={isAiProcessing}
          />
          <textarea
            placeholder="Description"
            rows={1}
            className="w-full text-[13px] text-gray-600 dark:text-gray-400 placeholder:text-gray-400 dark:placeholder:text-gray-500 focus:outline-none resize-none bg-transparent"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            disabled={isAiProcessing}
          />
        </div>

        <div className="flex items-center gap-2 mb-3">
            {/* Due Date */}
            <button 
                type="button" 
                className={`flex items-center gap-1 px-2 py-1 rounded border border-gray-200 dark:border-[#404040] text-xs text-gray-500 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-[#363636] transition-colors ${dueDate ? 'text-[#058527] bg-green-50 dark:bg-[#058527]/10 border-green-200 dark:border-green-800' : ''}`}
                onClick={() => {
                    const tomorrow = new Date();
                    tomorrow.setDate(tomorrow.getDate() + 1);
                    setDueDate(dueDate ? '' : tomorrow.toISOString().split('T')[0]);
                }}
            >
              <Calendar size={14} />
              {dueDate ? 'Tomorrow' : 'Due date'}
            </button>

            {/* Priority */}
            <div className="relative group">
                <button type="button" className={`flex items-center gap-1 px-2 py-1 rounded border border-gray-200 dark:border-[#404040] text-xs hover:bg-gray-50 dark:hover:bg-[#363636] transition-colors ${priority !== Priority.P4 ? priorityColors[priority] : 'text-gray-500 dark:text-gray-400'}`}>
                    <Flag size={14} fill={priority === Priority.P4 ? 'none' : 'currentColor'} />
                    Priority
                </button>
                <div className="absolute top-full left-0 mt-1 w-32 bg-white dark:bg-[#282828] border border-gray-200 dark:border-[#363636] rounded-lg shadow-xl hidden group-hover:block z-50 py-1">
                    {[Priority.P1, Priority.P2, Priority.P3, Priority.P4].map(p => (
                        <div key={p} onClick={() => setPriority(p)} className="flex items-center gap-2 px-3 py-2 hover:bg-gray-100 dark:hover:bg-[#363636] cursor-pointer text-xs text-gray-700 dark:text-gray-300">
                             <Flag size={14} className={priorityColors[p]} fill={p === Priority.P4 ? 'none' : 'currentColor'}/> 
                             Priority {p}
                        </div>
                    ))}
                </div>
            </div>
        </div>

        <div className="flex items-center justify-between border-t border-gray-100 dark:border-[#363636] pt-3">
            <div className="relative group">
                <button type="button" className="flex items-center gap-1.5 px-2 py-1.5 rounded hover:bg-gray-100 dark:hover:bg-[#363636] text-xs text-gray-600 dark:text-gray-400 font-medium transition-colors">
                    <Hash size={14} />
                    {projects.find(p => p.id === projectId)?.name || 'Inbox'}
                </button>
                 <div className="absolute top-full left-0 mt-1 w-48 max-h-48 overflow-y-auto scrollbar-hide bg-white dark:bg-[#282828] border border-gray-200 dark:border-[#363636] rounded-lg shadow-xl hidden group-hover:block z-50">
                    <div onClick={() => setProjectId('inbox')} className="px-3 py-2 hover:bg-gray-100 dark:hover:bg-[#363636] cursor-pointer text-xs truncate flex items-center gap-2 text-gray-700 dark:text-gray-300">
                        <Hash size={14} className="text-gray-400" /> Inbox
                    </div>
                    {projects.map(p => (
                        <div key={p.id} onClick={() => setProjectId(p.id)} className="px-3 py-2 hover:bg-gray-100 dark:hover:bg-[#363636] cursor-pointer text-xs truncate flex items-center gap-2 text-gray-700 dark:text-gray-300">
                            <span className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{backgroundColor: p.color}}></span>
                            {p.name}
                        </div>
                    ))}
                </div>
            </div>

          <div className="flex items-center gap-2">
            <button
              type="button"
              onClick={onCancel}
              className="px-3 py-1.5 rounded-[5px] text-[13px] font-semibold text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-[#363636] bg-gray-50 dark:bg-[#363636] transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!content.trim() || isAiProcessing}
              className={`px-3 py-1.5 rounded-[5px] text-[13px] font-semibold text-white transition-colors ${!content.trim() ? 'bg-[#ffc2bd] dark:bg-[#6b2a26] cursor-not-allowed' : 'bg-[#db4c3f] hover:bg-[#b03d32]'}`}
            >
              Add task
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

export default AddTask;

import React, { useState, useRef, useEffect } from 'react';
import { Check, MoreHorizontal, Calendar, Edit2, Trash2, Hash, Tag, Repeat, Flame, Save, X } from 'lucide-react';
import { FlowItem as FlowItemType, Priority } from '../types';

interface FlowItemProps {
  item: FlowItemType;
  onComplete?: (id: string) => void;
  onDelete: (id: string) => void;
  onUpdate?: (updates: Partial<FlowItemType>) => void;
}

const FlowItem: React.FC<FlowItemProps> = ({ item, onComplete, onDelete, onUpdate }) => {
  const [showMenu, setShowMenu] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(item.content);
  const [editDescription, setEditDescription] = useState(item.description || '');

  const menuRef = useRef<HTMLDivElement>(null);

  const isTask = item.type === 'TASK';
  const isHabit = item.type === 'HABIT';

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSave = () => {
      if (onUpdate) {
          onUpdate({
              content: editContent,
              description: editDescription
          });
      }
      setIsEditing(false);
  };

  // Priority styles for the circle border/fill
  const priorityStyle = {
      [Priority.P1]: 'border-[#d1453b] bg-[#fdf2f2] dark:bg-[#d1453b]/10 text-[#d1453b]',
      [Priority.P2]: 'border-[#eb8909] bg-[#fff8e6] dark:bg-[#eb8909]/10 text-[#eb8909]',
      [Priority.P3]: 'border-[#246fe0] bg-[#e6f0ff] dark:bg-[#246fe0]/10 text-[#246fe0]',
      [Priority.P4]: 'border-gray-400 dark:border-gray-500 hover:border-gray-500 dark:hover:border-gray-400 text-gray-500',
  };

  const getPriorityColor = (p?: Priority) => {
      switch(p) {
          case Priority.P1: return '#d1453b';
          case Priority.P2: return '#eb8909';
          case Priority.P3: return '#246fe0';
          default: return 'gray';
      }
  };

  const MenuDropdown = () => (
      <div 
        ref={menuRef}
        className="absolute right-0 top-8 w-40 bg-white dark:bg-[#282828] rounded shadow-[0_4px_12px_rgba(0,0,0,0.1)] border border-gray-100 dark:border-[#363636] py-1 z-20 animate-in fade-in zoom-in-95 duration-100"
      >
        <button 
            onClick={(e) => {
                e.stopPropagation();
                setIsEditing(true);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-[13px] text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-[#363636] flex items-center gap-2"
        >
            <Edit2 size={14} />
            Edit task
        </button>
        <div className="h-px bg-gray-100 dark:bg-[#363636] my-1" />
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onDelete(item.id);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-[13px] text-red-600 hover:bg-red-50 dark:hover:bg-[#3d1f1f] flex items-center gap-2"
        >
            <Trash2 size={14} />
            Delete
        </button>
      </div>
  );

  if (isEditing) {
      return (
          <div className="border border-gray-200 dark:border-[#363636] rounded p-3 bg-white dark:bg-[#1f1f1f] shadow-sm mb-2 -mx-3">
              <input 
                  autoFocus
                  className="w-full text-[14px] font-medium text-[#202020] dark:text-gray-200 placeholder:text-gray-400 bg-transparent focus:outline-none mb-2"
                  value={editContent}
                  onChange={e => setEditContent(e.target.value)}
              />
              <textarea 
                  className="w-full text-[13px] text-gray-600 dark:text-gray-400 placeholder:text-gray-400 bg-transparent focus:outline-none resize-none"
                  rows={2}
                  value={editDescription}
                  onChange={e => setEditDescription(e.target.value)}
                  placeholder="Description"
              />
              <div className="flex justify-end gap-2 mt-2 pt-2 border-t border-gray-100 dark:border-[#363636]">
                  <button onClick={() => setIsEditing(false)} className="px-3 py-1.5 text-xs font-semibold text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-[#363636] rounded">Cancel</button>
                  <button onClick={handleSave} className="px-3 py-1.5 text-xs font-semibold text-white bg-[#db4c3f] hover:bg-[#b03d32] rounded">Save</button>
              </div>
          </div>
      );
  }

  return (
    <div className="group relative flex items-start gap-3 py-2.5 border-b border-[#f0f0f0] dark:border-[#303030] hover:bg-gray-50 dark:hover:bg-[#2a2a2a] -mx-3 px-3 rounded transition-colors">

        {/* Checkbox / Habit Toggle */}
        <button
          onClick={(e) => {
              e.stopPropagation();
              onComplete && onComplete(item.id);
          }}
          className={`
            mt-0.5 flex-shrink-0 w-[18px] h-[18px] rounded-full border-[1.5px] flex items-center justify-center transition-all duration-200
            ${item.isCompleted 
                ? 'bg-gray-300 border-gray-300 dark:bg-gray-600 dark:border-gray-600 text-white' 
                : `${priorityStyle[item.priority || Priority.P4]} bg-transparent group/check`
            }
          `}
        >
          {item.isCompleted ? (
              <Check size={12} strokeWidth={3} />
          ) : (
              <Check size={10} strokeWidth={3} className="opacity-0 group-hover/check:opacity-100" style={{ color: getPriorityColor(item.priority) }} />
          )}
        </button>

        <div className="flex-1 min-w-0">
           {/* Content */}
           <div className={`text-[14px] leading-snug break-words ${item.isCompleted ? 'line-through text-gray-400 dark:text-gray-500' : 'text-[#202020] dark:text-gray-200'}`}>
                {item.content}
                {isHabit && item.streak ? <span className="ml-2 text-xs text-orange-500 font-medium">🔥 {item.streak}</span> : null}
           </div>

           {/* Description */}
           {item.description && (
               <div className="text-[12px] text-gray-500 dark:text-gray-400 mt-0.5 line-clamp-2">
                   {item.description}
               </div>
           )}

           {/* Meta Row */}
           <div className="flex flex-wrap items-center gap-2 mt-1">
               {/* Date */}
               {item.dueDate && (
                   <div className={`flex items-center gap-1 text-[12px] ${item.dueDate < new Date().toISOString().split('T')[0] ? 'text-[#d1453b]' : 'text-gray-500 dark:text-gray-500'}`}>
                       <Calendar size={12} />
                       <span>{new Date(item.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                   </div>
               )}

               {/* Habit Frequency */}
               {isHabit && item.frequency && (
                   <div className="flex items-center gap-1 text-[12px] text-gray-500 dark:text-gray-500">
                       <Repeat size={12} />
                       <span className="capitalize">{item.frequency}</span>
                   </div>
               )}

               {/* Tags */}
               {item.tags?.map(tag => (
                   <div key={tag} className="flex items-center gap-0.5 text-[12px] text-gray-500 dark:text-gray-500">
                        <Tag size={12} className="opacity-70" />
                        {tag}
                   </div>
               ))}
           </div>
        </div>

        {/* Actions (Hidden until hover) */}
        <div className="relative opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                className="p-1 text-gray-400 hover:text-gray-800 dark:hover:text-gray-200 rounded hover:bg-gray-200 dark:hover:bg-[#363636]"
            >
                <MoreHorizontal size={16} />
            </button>
            {showMenu && <MenuDropdown />}
        </div>
    </div>
  );
};

export default FlowItem;

export enum Priority {
  P1 = 1, // Critical
  P2 = 2, // High
  P3 = 3, // Medium
  P4 = 4  // Low
}

export type ItemType = 'TASK' | 'NOTE' | 'HABIT';
export type HabitFrequency = 'daily' | 'weekly' | 'monthly';

export interface FlowItem {
  id: string;
  type: ItemType;
  content: string;
  description?: string; // Additional context or AI summary

  // Task specific
  isCompleted?: boolean;
  priority?: Priority;
  dueDate?: string; // ISO Date string
  projectId?: string; // Linked Project ID

  // Habit specific
  streak?: number;
  lastCompletedDate?: string; // YYYY-MM-DD
  frequency?: HabitFrequency;
  history?: string[]; // Array of YYYY-MM-DD completion dates for graph

  // Metadata
  tags?: string[];
  createdAt: string;
  mood?: 'neutral' | 'positive' | 'negative' | 'focused' | 'anxious'; // AI inferred mood
}

export interface Project {
  id: string;
  name: string;
  color: string;
}

export interface ParsedTask {
  content: string;
  description?: string;
  priority?: Priority;
  dueDate?: string;
  projectName?: string;
}

export type Task = FlowItem;

export interface ViewState {
  type: 'HOME' | 'TASKS' | 'HABITS' | 'JOURNAL' | 'PROJECT' | 'TAG';
  id?: string; // projectId or tagName
}

// Gemini Parsing Result
export interface ProcessedInput {
  items: Array<{
    type: ItemType;
    content: string;
    description?: string;
