import React from 'react';
import { FlowItem, Priority } from '../types';
import { Flame, Calendar, ArrowRight, CheckCircle2, Trophy, Activity } from 'lucide-react';

interface HomeDashboardProps {
  items: FlowItem[];
  username?: string;
  onNavigate: (view: any) => void;
  onComplete: (id: string) => void;
}

const HomeDashboard: React.FC<HomeDashboardProps> = ({ items, username = "there", onNavigate, onComplete }) => {
  const today = new Date().toISOString().split('T')[0];

  // Logic for Habits
  const habits = items.filter(i => i.type === 'HABIT');
  const activeHabits = habits.filter(h => !h.history?.includes(today)); // Not done today

  // Logic for Tasks (Due today or overdue)
  const urgentTasks = items.filter(i => 
    i.type === 'TASK' && 
    !i.isCompleted && 
    (i.priority === Priority.P1 || (i.dueDate && i.dueDate <= today))
  ).sort((a, b) => (a.priority || 4) - (b.priority || 4));

  // Consistency Graph Logic (Last 14 days)
  const getConsistencyData = () => {
    const dates = [];
    const now = new Date();
    for (let i = 13; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      dates.push(d.toISOString().split('T')[0]);
    }
    return dates.map(date => {
      // Calculate 'intensity' based on habits completed that day
      const completedCount = habits.reduce((acc, habit) => {
        return acc + (habit.history?.includes(date) ? 1 : 0);
      }, 0);
      return { date, count: completedCount };
    });
  };

  const consistencyData = getConsistencyData();

  return (
    <div className="p-6 md:p-8 max-w-5xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Welcome Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-800 dark:text-white">
            Good {new Date().getHours() < 12 ? 'morning' : new Date().getHours() < 18 ? 'afternoon' : 'evening'}, {username}.
          </h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1">
            You have {urgentTasks.length} urgent tasks and {activeHabits.length} habits remaining today.
          </p>
        </div>
        <div className="flex items-center gap-2 text-sm font-medium bg-violet-50 dark:bg-violet-900/20 text-violet-600 dark:text-violet-300 px-4 py-2 rounded-full border border-violet-100 dark:border-violet-800">
           <Activity size={16} />
           <span>System Status: Focused</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">

        {/* Consistency Graph Card */}
        <div className="md:col-span-2 bg-white dark:bg-dark-surface rounded-2xl p-6 shadow-sm border border-slate-100 dark:border-dark-border">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-semibold text-slate-700 dark:text-slate-200 flex items-center gap-2">
              <Flame className="text-orange-500" size={20} />
              Consistency Graph
            </h3>
            <span className="text-xs text-slate-400">Last 14 Days</span>
          </div>

          <div className="flex items-end justify-between gap-2 h-32 w-full">
            {consistencyData.map((d, i) => (
              <div key={d.date} className="flex flex-col items-center gap-2 flex-1 group">
                <div 
                  className={`w-full rounded-t-md transition-all duration-500 hover:opacity-80 relative group-hover:scale-110 ${d.count > 0 ? 'bg-violet-500' : 'bg-slate-100 dark:bg-slate-700'}`}
                  style={{ 
                    height: `${Math.max(10, Math.min(100, d.count * 25))}%`,
                    opacity: d.count === 0 ? 0.3 : 0.5 + (d.count * 0.1) 
                  }}
                >
                    {/* Tooltip */}
                    <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2 py-1 bg-black text-white text-xs rounded opacity-0 group-hover:opacity-100 whitespace-nowrap z-10 pointer-events-none transition-opacity">
                        {new Date(d.date).toLocaleDateString('en-US', {weekday: 'short', day: 'numeric'})}: {d.count} habits
                    </div>
                </div>
                <span className="text-[10px] text-slate-400 font-medium">
                  {new Date(d.date).toLocaleDateString('en-US', {weekday: 'narrow'})}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Quick Stats / Trophy */}
        <div className="bg-gradient-to-br from-violet-500 to-indigo-600 rounded-2xl p-6 text-white shadow-lg shadow-violet-500/20 flex flex-col justify-between">
           <div>
               <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center mb-4 backdrop-blur-sm">
                   <Trophy size={24} className="text-yellow-300" />
               </div>
               <h3 className="text-xl font-bold mb-1">Current Streak</h3>
               <p className="text-violet-100 text-sm">Keep the momentum going!</p>
           </div>
           <div className="mt-4">
               <div className="text-4xl font-bold">
                   {Math.max(...habits.map(h => h.streak || 0), 0)} <span className="text-lg font-normal opacity-70">days</span>
               </div>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Urgent Tasks */}
          <div>
              <div className="flex items-center justify-between mb-4">
                  <h2 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
                      <Calendar size={18} className="text-rose-500" />
                      Up Next
                  </h2>
                  <button 
                    onClick={() => onNavigate({type: 'TASKS'})}
                    className="text-sm text-violet-600 dark:text-violet-400 hover:underline flex items-center gap-1"
                  >
                      View all <ArrowRight size={14} />
                  </button>
              </div>

              <div className="space-y-3">
                  {urgentTasks.length === 0 ? (
                      <div className="text-center py-8 bg-white dark:bg-dark-surface rounded-xl border border-slate-100 dark:border-dark-border border-dashed text-slate-400">
                          No urgent tasks. You're clear!
                      </div>
                  ) : (
                      urgentTasks.slice(0, 4).map(task => (
                          <div key={task.id} className="group bg-white dark:bg-dark-surface p-4 rounded-xl shadow-sm border border-slate-100 dark:border-dark-border hover:border-violet-200 dark:hover:border-violet-900 transition-colors flex items-start gap-3">
                              <button 
                                onClick={() => onComplete(task.id)}
                                className="mt-1 w-5 h-5 rounded-full border-2 border-rose-100 dark:border-rose-900/30 text-transparent hover:border-rose-500 hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center"
                              >
                                  <CheckCircle2 size={12} />
                              </button>
                              <div className="flex-1">
                                  <div className="text-sm font-medium text-slate-800 dark:text-slate-200">{task.content}</div>
                                  {task.dueDate && (
                                      <div className="text-xs text-rose-500 mt-1 font-medium">Due {new Date(task.dueDate).toLocaleDateString()}</div>
                                  )}
                              </div>
                              <div className="px-2 py-1 bg-slate-100 dark:bg-slate-800 text-slate-500 text-[10px] rounded uppercase font-bold tracking-wider">
                                  {task.priority === 1 ? 'Urgent' : 'High'}
                              </div>
                          </div>
                      ))
                  )}
              </div>
          </div>

          {/* Active Habits */}
          <div>
              <div className="flex items-center justify-between mb-4">
                  <h2 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
                      <Flame size={18} className="text-orange-500" />
                      Daily Rituals
                  </h2>
                  <button 
                    onClick={() => onNavigate({type: 'HABITS'})}
                    className="text-sm text-violet-600 dark:text-violet-400 hover:underline flex items-center gap-1"
                  >
                      Manage <ArrowRight size={14} />
                  </button>
              </div>

              <div className="space-y-3">
                 {habits.slice(0, 5).map(habit => {
                     const isDoneToday = habit.history?.includes(today);
                     return (
                        <div key={habit.id} className="flex items-center justify-between bg-white dark:bg-dark-surface p-4 rounded-xl shadow-sm border border-slate-100 dark:border-dark-border">
                            <div className="flex items-center gap-3">
                                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${isDoneToday ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'}`}>
                                    <Flame size={16} fill={isDoneToday ? "currentColor" : "none"} />
                                </div>
                                <div>
                                    <div className="text-sm font-medium text-slate-800 dark:text-slate-200">{habit.content}</div>
                                    <div className="text-xs text-slate-400">
                                        {habit.streak} day streak
                                    </div>
                                </div>
                            </div>
                            <button 
                                onClick={() => onComplete(habit.id)}
                                className={`px-4 py-1.5 rounded-full text-xs font-semibold transition-colors ${
                                    isDoneToday 
                                    ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' 
                                    : 'bg-slate-100 hover:bg-slate-200 text-slate-600 dark:bg-slate-800 dark:hover:bg-slate-700 dark:text-slate-300'
                                }`}
                            >
                                {isDoneToday ? 'Done' : 'Complete'}
                            </button>
                        </div>
                     );
                 })}
                 {habits.length === 0 && (
                     <div className="text-center py-8 text-slate-400 text-sm">
                         No habits tracked yet.
                     </div>
                 )}
              </div>
          </div>
      </div>
    </div>
  );
};

export default HomeDashboard;

