import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SendHorizontal, Keyboard, MicOff } from 'lucide-react';
import { blobToBase64, processVoiceEntry, processTextEntry } from '../services/geminiService';
import { ProcessedInput } from '../types';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const [textInput, setTextInput] = useState('');
  const [liveTranscript, setLiveTranscript] = useState('');

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const recognitionRef = useRef<any>(null);

  // Initialize Web Speech API for live transcription visualization
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;

        recognitionRef.current.onresult = (event: any) => {
            let interimTranscript = '';
            for (let i = event.resultIndex; i < event.results.length; ++i) {
                if (event.results[i].isFinal) {
                    setLiveTranscript(prev => prev + event.results[i][0].transcript + ' ');
                } else {
                    interimTranscript += event.results[i][0].transcript;
                }
            }
            // Update UI with current live text
            const display = document.getElementById('live-transcript-display');
            if (display) {
                display.innerText = (event.results[0]?.isFinal ? '' : '') + interimTranscript;
            }
        };
    }
  }, []);

  const startRecording = async () => {
    try {
      setLiveTranscript('');
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunksRef.current.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        setIsProcessing(true);
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/webm' });

        // Stop all tracks to release mic
        stream.getTracks().forEach(track => track.stop());

        try {
          const base64 = await blobToBase64(audioBlob);
          const result = await processVoiceEntry(base64);
          if (result) {
            onProcessed(result);
          }
        } catch (err) {
          console.error("Processing failed", err);
          alert("Could not process audio. Please try again.");
        } finally {
          setIsProcessing(false);
          setLiveTranscript('');
        }
      };

      mediaRecorder.start();
      recognitionRef.current?.start(); // Start live transcription
      setIsRecording(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Microphone access is required for voice capture.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      recognitionRef.current?.stop();
      setIsRecording(false);
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!textInput.trim()) return;

    setIsProcessing(true);
    try {
        const result = await processTextEntry(textInput);
        if (result) onProcessed(result);
        setTextInput('');
        setShowTextInput(false);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-[260px] right-0 p-6 flex flex-col items-center justify-end z-20 pointer-events-none transition-all duration-200">

       {/* Live Transcript Bubble */}
       {isRecording && (
           <div className="pointer-events-auto mb-6 bg-slate-900/80 backdrop-blur-md text-white px-6 py-4 rounded-2xl shadow-2xl max-w-lg w-full text-center animate-in slide-in-from-bottom-10 fade-in duration-300">
               <div className="text-xs text-slate-400 uppercase tracking-widest font-bold mb-2 flex items-center justify-center gap-2">
                   <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></span>
                   Live Transcribe
               </div>
               <p id="live-transcript-display" className="text-lg font-medium min-h-[1.5em]">
                   {liveTranscript || "Listening..."}
               </p>
           </div>
       )}

       {/* Text Input Overlay */}
       {showTextInput && (
           <div className="pointer-events-auto w-full max-w-2xl mb-4 bg-white dark:bg-dark-surface rounded-2xl shadow-xl border border-slate-200 dark:border-dark-border p-2 animate-in slide-in-from-bottom-5">
               <form onSubmit={handleTextSubmit} className="flex gap-2">
                   <input 
                      autoFocus
                      className="flex-1 px-4 py-3 bg-transparent outline-none text-slate-800 dark:text-gray-200 placeholder:text-slate-400"
                      placeholder="Type your thought..."
                      value={textInput}
                      onChange={e => setTextInput(e.target.value)}
                      disabled={isProcessing}
                   />
                   <button 
                      type="submit" 
                      disabled={isProcessing || !textInput.trim()}
                      className="p-3 bg-violet-600 text-white rounded-xl hover:bg-violet-700 transition-colors disabled:opacity-50"
                   >
                       {isProcessing ? <Loader2 className="animate-spin" size={20}/> : <SendHorizontal size={20}/>}
                   </button>
               </form>
           </div>
       )}

      <div className="pointer-events-auto flex items-center gap-4">
        {/* Keyboard Toggle */}
        <button 
            onClick={() => setShowTextInput(!showTextInput)}
            className="bg-white dark:bg-dark-surface text-slate-500 dark:text-gray-400 p-3 rounded-full shadow-lg border border-slate-100 dark:border-dark-border hover:text-violet-600 dark:hover:text-violet-400 transition-colors"
        >
            <Keyboard size={20} />
        </button>

        {/* Main Mic Button */}
        <button
            onClick={isRecording ? stopRecording : startRecording}
            disabled={isProcessing}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-xl transition-all duration-300
            ${isRecording 
                ? 'bg-red-500 text-white recording-pulse scale-110' 
                : isProcessing 
                    ? 'bg-slate-100 dark:bg-dark-surface text-slate-400' 
                    : 'bg-violet-600 text-white hover:bg-violet-700 hover:scale-105 shadow-violet-500/30'
            }
            `}
        >
            {isProcessing ? (
                <Loader2 size={24} className="animate-spin" />
            ) : isRecording ? (
                <Square size={24} fill="currentColor" />
            ) : (
                <Mic size={28} />
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-slate-400 dark:text-gray-500 text-center transition-opacity duration-300">
        {isRecording ? "Tap to stop" : isProcessing ? "Processing..." : showTextInput ? "" : "Tap to speak"}
      </div>
    </div>
  );
};

export default VoiceCapture;

import React, { useState, useRef, useEffect } from 'react';
import { Check, MoreHorizontal, Calendar, Edit2, Trash2, Tag, Repeat, Clock } from 'lucide-react';
import { FlowItem as FlowItemType, Priority } from '../types';

interface FlowItemProps {
  item: FlowItemType;
  onComplete?: (id: string) => void;
  onDelete: (id: string) => void;
  onUpdate?: (updates: Partial<FlowItemType>) => void;
}

const FlowItem: React.FC<FlowItemProps> = ({ item, onComplete, onDelete, onUpdate }) => {
  const [showMenu, setShowMenu] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(item.content);
  const [editDescription, setEditDescription] = useState(item.description || '');

  const menuRef = useRef<HTMLDivElement>(null);
  const isHabit = item.type === 'HABIT';

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSave = () => {
      if (onUpdate) {
          onUpdate({
              content: editContent,
              description: editDescription
          });
      }
      setIsEditing(false);
  };

  // New Color System
  const priorityColor = {
      [Priority.P1]: 'border-rose-500 bg-rose-50 dark:bg-rose-900/10 text-rose-700',
      [Priority.P2]: 'border-amber-500 bg-amber-50 dark:bg-amber-900/10 text-amber-700',
      [Priority.P3]: 'border-blue-500 bg-blue-50 dark:bg-blue-900/10 text-blue-700',
      [Priority.P4]: 'border-slate-300 dark:border-slate-600 bg-white dark:bg-dark-surface text-slate-700',
  };

  const MenuDropdown = () => (
      <div 
        ref={menuRef}
        className="absolute right-0 top-8 w-40 bg-white dark:bg-dark-surface rounded-xl shadow-lg border border-slate-100 dark:border-dark-border py-1 z-20 animate-in fade-in zoom-in-95 duration-100"
      >
        <button 
            onClick={(e) => {
                e.stopPropagation();
                setIsEditing(true);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-800 flex items-center gap-2"
        >
            <Edit2 size={14} />
            Edit
        </button>
        <div className="h-px bg-slate-100 dark:bg-slate-800 my-1" />
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onDelete(item.id);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/20 flex items-center gap-2"
        >
            <Trash2 size={14} />
            Delete
        </button>
      </div>
  );

  if (isEditing) {
      return (
          <div className="border border-violet-200 dark:border-violet-900 rounded-xl p-4 bg-white dark:bg-dark-surface shadow-md mb-3">
              <input 
                  autoFocus
                  className="w-full text-sm font-semibold text-slate-800 dark:text-slate-200 placeholder:text-slate-400 bg-transparent focus:outline-none mb-2"
                  value={editContent}
                  onChange={e => setEditContent(e.target.value)}
              />
              <textarea 
                  className="w-full text-xs text-slate-600 dark:text-slate-400 placeholder:text-slate-400 bg-transparent focus:outline-none resize-none"
                  rows={2}
                  value={editDescription}
                  onChange={e => setEditDescription(e.target.value)}
                  placeholder="Add details..."
              />
              <div className="flex justify-end gap-2 mt-3 pt-2 border-t border-slate-100 dark:border-dark-border">
                  <button onClick={() => setIsEditing(false)} className="px-3 py-1.5 text-xs font-semibold text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg">Cancel</button>
                  <button onClick={handleSave} className="px-3 py-1.5 text-xs font-semibold text-white bg-violet-600 hover:bg-violet-700 rounded-lg">Save</button>
              </div>
          </div>
      );
  }

  return (
    <div className="group relative flex items-center gap-4 p-4 mb-3 bg-white dark:bg-dark-surface border border-slate-100 dark:border-dark-border rounded-xl shadow-sm hover:shadow-md transition-all duration-200">

        {/* Checkbox */}
        <button
          onClick={(e) => {
              e.stopPropagation();
              onComplete && onComplete(item.id);
          }}
          className={`
            flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300
            ${item.isCompleted 
                ? 'bg-slate-300 border-slate-300 dark:bg-slate-700 dark:border-slate-700 text-white' 
                : `${priorityColor[item.priority || Priority.P4]} hover:scale-110 bg-transparent`
            }
          `}
        >
          {item.isCompleted && <Check size={14} strokeWidth={3} />}
        </button>

        <div className="flex-1 min-w-0">
           {/* Content */}
           <div className={`text-sm font-medium leading-snug break-words flex items-center gap-2 ${item.isCompleted ? 'line-through text-slate-400' : 'text-slate-800 dark:text-slate-200'}`}>
                {item.content}
                {isHabit && item.streak ? (
                    <span className="text-[10px] font-bold px-1.5 py-0.5 bg-orange-100 text-orange-600 rounded-full flex items-center gap-1">
                        🔥 {item.streak}
                    </span>
                ) : null}
           </div>

           {/* Description */}
           {item.description && (
               <div className="text-xs text-slate-500 dark:text-slate-400 mt-1 line-clamp-1">
                   {item.description}
               </div>
           )}

           {/* Meta Row */}
           <div className="flex flex-wrap items-center gap-3 mt-2">
               {/* Date */}
               {item.dueDate && (
                   <div className={`flex items-center gap-1 text-[10px] font-medium ${item.dueDate < new Date().toISOString().split('T')[0] ? 'text-rose-500' : 'text-slate-400'}`}>
                       <Calendar size={10} />
                       <span>{new Date(item.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                   </div>
               )}

               {/* Habit Frequency */}
               {isHabit && item.frequency && (
                   <div className="flex items-center gap-1 text-[10px] text-slate-400">
                       <Repeat size={10} />
                       <span className="capitalize">{item.frequency}</span>
                   </div>
               )}

               {/* Tags */}
               {item.tags?.map(tag => (
                   <div key={tag} className="flex items-center gap-0.5 text-[10px] bg-slate-50 dark:bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded">
                        <Tag size={8} />
                        {tag}
                   </div>
               ))}
           </div>
        </div>

        {/* Actions (Hidden until hover) */}
        <div className="opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                className="p-2 text-slate-400 hover:text-slate-700 dark:hover:text-slate-200 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800"
            >
                <MoreHorizontal size={18} />
            </button>
            {showMenu && <MenuDropdown />}
        </div>
    </div>
  );
};

