import React, { useState, useRef, useEffect } from 'react';
import { Calendar, Flag, Hash, Sparkles, X } from 'lucide-react';
import { Priority, Project } from '../types';
import { parseTaskWithGemini } from '../services/geminiService';

interface AddTaskProps {
  projects: Project[];
  defaultProjectId: string;
  onAddTask: (task: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => void;
  onCancel: () => void;
}

const AddTask: React.FC<AddTaskProps> = ({ projects, defaultProjectId, onAddTask, onCancel }) => {
  const [content, setContent] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<Priority>(Priority.P4);
  const [projectId, setProjectId] = useState<string>(defaultProjectId);
  const [dueDate, setDueDate] = useState<string>('');

  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!content.trim()) return;

    onAddTask({
      content,
      description: description.trim() || undefined,
      priority,
      projectId,
      dueDate: dueDate || undefined
    });
    setContent('');
    setDescription('');
  };

  const priorityColors = {
    [Priority.P1]: 'text-rose-500',
    [Priority.P2]: 'text-amber-500',
    [Priority.P3]: 'text-blue-500',
    [Priority.P4]: 'text-slate-500',
  };

  return (
    <div className="border border-violet-200 dark:border-violet-900 rounded-2xl p-4 bg-white dark:bg-dark-surface shadow-xl shadow-violet-500/5 mb-6 transition-all relative z-10 animate-in fade-in slide-in-from-top-4">
      <form onSubmit={handleSubmit}>
        <div className="mb-4">
          <input
            ref={inputRef}
            type="text"
            placeholder="What's on your mind?"
            className="w-full text-lg font-semibold text-slate-800 dark:text-slate-100 placeholder:text-slate-300 dark:placeholder:text-slate-600 focus:outline-none bg-transparent mb-2"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            disabled={isAiProcessing}
          />
          <textarea
            placeholder="Description (optional)"
            rows={2}
            className="w-full text-sm text-slate-600 dark:text-slate-400 placeholder:text-slate-300 dark:placeholder:text-slate-600 focus:outline-none resize-none bg-transparent"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            disabled={isAiProcessing}
          />
        </div>

        <div className="flex items-center gap-3 mb-4 flex-wrap">
            {/* Due Date */}
            <button 
                type="button" 
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border text-xs font-medium transition-colors ${dueDate ? 'bg-green-50 border-green-200 text-green-700' : 'border-slate-200 dark:border-dark-border text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'}`}
                onClick={() => {
                    const tomorrow = new Date();
                    tomorrow.setDate(tomorrow.getDate() + 1);
                    setDueDate(dueDate ? '' : tomorrow.toISOString().split('T')[0]);
                }}
            >
              <Calendar size={14} />
              {dueDate ? 'Tomorrow' : 'Set Due Date'}
            </button>

            {/* Priority */}
            <div className="relative group">
                <button type="button" className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-slate-200 dark:border-dark-border text-xs font-medium hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors ${priority !== Priority.P4 ? priorityColors[priority] : 'text-slate-500'}`}>
                    <Flag size={14} fill={priority === Priority.P4 ? 'none' : 'currentColor'} />
                    Priority
                </button>
                <div className="absolute top-full left-0 mt-2 w-32 bg-white dark:bg-dark-surface border border-slate-100 dark:border-dark-border rounded-xl shadow-xl hidden group-hover:block z-50 py-1">
                    {[Priority.P1, Priority.P2, Priority.P3, Priority.P4].map(p => (
                        <div key={p} onClick={() => setPriority(p)} className="flex items-center gap-2 px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer text-xs text-slate-700 dark:text-slate-300">
                             <Flag size={14} className={priorityColors[p]} fill={p === Priority.P4 ? 'none' : 'currentColor'}/> 
                             Priority {p}
                        </div>
                    ))}
                </div>
            </div>

            {/* Project Selector */}
            <div className="relative group">
                <button type="button" className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-slate-200 dark:border-dark-border text-xs font-medium hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-500 transition-colors">
                    <Hash size={14} />
                    {projects.find(p => p.id === projectId)?.name || 'Inbox'}
                </button>
                 <div className="absolute top-full left-0 mt-2 w-48 max-h-48 overflow-y-auto scrollbar-hide bg-white dark:bg-dark-surface border border-slate-100 dark:border-dark-border rounded-xl shadow-xl hidden group-hover:block z-50">
                    <div onClick={() => setProjectId('inbox')} className="px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer text-xs truncate flex items-center gap-2 text-slate-700 dark:text-slate-300">
                        <Hash size={14} className="text-slate-400" /> Inbox
                    </div>
                    {projects.map(p => (
                        <div key={p.id} onClick={() => setProjectId(p.id)} className="px-3 py-2 hover:bg-slate-50 dark:hover:bg-slate-800 cursor-pointer text-xs truncate flex items-center gap-2 text-slate-700 dark:text-slate-300">
                            <span className="w-2 h-2 rounded-full flex-shrink-0" style={{backgroundColor: p.color}}></span>
                            {p.name}
                        </div>
                    ))}
                </div>
            </div>
        </div>

        <div className="flex items-center justify-end gap-3 pt-4 border-t border-slate-100 dark:border-dark-border">
            <button
              type="button"
              onClick={onCancel}
              className="px-4 py-2 rounded-lg text-sm font-semibold text-slate-500 hover:text-slate-800 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!content.trim() || isAiProcessing}
              className={`px-6 py-2 rounded-lg text-sm font-semibold text-white transition-all shadow-lg shadow-violet-500/30 ${!content.trim() ? 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed shadow-none' : 'bg-violet-600 hover:bg-violet-700 hover:scale-105'}`}
            >
              Add to Flow
            </button>
        </div>
      </form>
    </div>
  );
};

export default AddTask;

import React, { useState, useEffect, useMemo } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Menu, Plus, LayoutGrid, Search, Bell, Moon, Sun, X, CheckCircle2 } from 'lucide-react';
import Sidebar from './components/Sidebar';
import VoiceCapture from './components/VoiceCapture';
import FlowItem from './components/FlowItem';
import AddTask from './components/AddTask';
import ProjectModal from './components/ProjectModal';
import HomeDashboard from './components/HomeDashboard';
import { FlowItem as FlowItemType, ViewState, ProcessedInput, Priority, Project, HabitFrequency } from './types';

const INITIAL_PROJECTS: Project[] = [
    { id: 'p-personal', name: 'Personal', color: '#8b5cf6' },
    { id: 'p-work', name: 'Work', color: '#ec4899' }
];

const INITIAL_ITEMS: FlowItemType[] = [
  {
    id: 'welcome-1',
    type: 'TASK',
    content: 'Welcome to EchoFlow',
    description: 'This is your new mental rhythm. It adapts to you.',
    priority: Priority.P1,
    createdAt: new Date().toISOString(),
    isCompleted: false,
    projectId: 'p-personal',
    tags: ['welcome']
  },
  {
      id: 'habit-1',
      type: 'HABIT',
      content: 'Morning Meditation',
      streak: 5,
      frequency: 'daily',
      history: [
          // Simulate some history for the graph
          new Date(Date.now() - 86400000).toISOString().split('T')[0],
          new Date(Date.now() - 172800000).toISOString().split('T')[0]
      ],
      createdAt: new Date().toISOString()
  }
];

const App: React.FC = () => {
  const [items, setItems] = useState<FlowItemType[]>(() => {
    const saved = localStorage.getItem('echoflow_items');
    return saved ? JSON.parse(saved) : INITIAL_ITEMS;
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('echoflow_projects');
    return saved ? JSON.parse(saved) : INITIAL_PROJECTS;
  });

  const [viewState, setViewState] = useState<ViewState>({ type: 'HOME' });
  const [habitTab, setHabitTab] = useState<HabitFrequency>('daily');
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);
  const [showAddTask, setShowAddTask] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const [darkMode, setDarkMode] = useState(() => {
      if (typeof window !== 'undefined') {
          return localStorage.getItem('echoflow_theme') === 'dark' || 
                 (!('echoflow_theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
      }
      return false;
  });

  // Toast State
  const [toast, setToast] = useState<{message: string, type: 'success' | 'info'} | null>(null);

  useEffect(() => {
    localStorage.setItem('echoflow_items', JSON.stringify(items));
    localStorage.setItem('echoflow_projects', JSON.stringify(projects));
  }, [items, projects]);

  // Dark Mode Effect
  useEffect(() => {
      if (darkMode) {
          document.documentElement.classList.add('dark');
          localStorage.setItem('echoflow_theme', 'dark');
      } else {
          document.documentElement.classList.remove('dark');
          localStorage.setItem('echoflow_theme', 'light');
      }
  }, [darkMode]);

  const showToast = (message: string, type: 'success' | 'info' = 'success') => {
      setToast({ message, type });
      setTimeout(() => setToast(null), 3000);
  };

  const handleProcessedInput = (result: ProcessedInput) => {
    const newItems: FlowItemType[] = result.items.map(item => ({
      id: uuidv4(),
      createdAt: new Date().toISOString(),
      type: item.type,
      content: item.content,
      description: item.description,
      priority: item.priority as Priority,
      dueDate: item.dueDate,
      mood: item.mood as any,
      tags: item.tags,
      streak: item.streak,
      frequency: item.frequency || 'daily', 
      isCompleted: false,
      projectId: 'inbox' // Default to inbox
    }));

    setItems(prev => [...newItems, ...prev]);
    showToast(`Captured ${newItems.length} item${newItems.length > 1 ? 's' : ''}`);
  };

  const handleAddTask = (taskData: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => {
    const newTask: FlowItemType = {
        id: uuidv4(),
        type: 'TASK',
        content: taskData.content,
        description: taskData.description,
        priority: taskData.priority,
        projectId: taskData.projectId === 'inbox' ? 'inbox' : taskData.projectId,
        dueDate: taskData.dueDate,
        createdAt: new Date().toISOString(),
        isCompleted: false,
        tags: [] 
    };
    setItems(prev => [newTask, ...prev]);
    setShowAddTask(false);
    showToast('Task added to flow');
  };

  const handleUpdateItem = (id: string, updates: Partial<FlowItemType>) => {
      setItems(prev => prev.map(item => item.id === id ? { ...item, ...updates } : item));
      showToast('Item updated', 'info');
  };

  const handleAddProject = (name: string, color: string) => {
    const newProject = { id: uuidv4(), name, color };
    setProjects(prev => [...prev, newProject]);
    showToast(`Project "${name}" created`);
  };

  const handleComplete = (id: string) => {
    setItems(prev => prev.map(item => {
      if (item.id !== id) return item;

      const isCompleting = !item.isCompleted;
      const today = new Date().toISOString().split('T')[0];

      if (item.type === 'HABIT') {
        const isDoneToday = item.history?.includes(today);

        let newHistory = item.history || [];
        let newStreak = item.streak || 0;

        if (isDoneToday) {
            // Uncheck
            newHistory = newHistory.filter(d => d !== today);
            newStreak = Math.max(0, newStreak - 1);
        } else {
            // Check
            newHistory = [...newHistory, today];
            newStreak = newStreak + 1;
            showToast('Habit tracked! 🔥');
        }

        return {
            ...item,
            streak: newStreak,
            history: newHistory,
            lastCompletedDate: isDoneToday ? undefined : today
        };
      }

      if (isCompleting) showToast('Task completed');
      return { ...item, isCompleted: isCompleting };
    }));
  };

  const handleDelete = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
    showToast('Item deleted', 'info');
  };

  const filteredItems = useMemo(() => {
    let baseItems = items;

    // Search Filter
    if (searchQuery.trim()) {
        const q = searchQuery.toLowerCase();
        baseItems = baseItems.filter(i => 
            i.content.toLowerCase().includes(q) || 
            i.description?.toLowerCase().includes(q) ||
            i.tags?.some(t => t.toLowerCase().includes(q))
        );
    }

    // View Logic Filter
    switch (viewState.type) {
        case 'HOME':
            // Dashboard handles its own filtering
            return baseItems;
        case 'TASKS':
             baseItems = baseItems.filter(i => i.type === 'TASK' && !i.isCompleted);
             break;
        case 'HABITS':
            baseItems = baseItems.filter(i => i.type === 'HABIT' && (i.frequency || 'daily') === habitTab);
            break;
        case 'JOURNAL':
            baseItems = baseItems.filter(i => i.type === 'NOTE');
            break;
        case 'PROJECT':
            baseItems = baseItems.filter(i => i.projectId === viewState.id && !i.isCompleted);
            break;
        case 'TAG':
            baseItems = baseItems.filter(i => i.tags?.includes(viewState.id || '') && !i.isCompleted);
            break;
    }
    return baseItems;
  }, [items, viewState, habitTab, searchQuery]);

  const getPageTitle = () => {
      if (searchQuery) return 'Search Results';
      switch (viewState.type) {
          case 'HOME': return 'Dashboard';
          case 'TASKS': return 'My Tasks';
          case 'HABITS': return 'Habits';
          case 'JOURNAL': return 'Journal';
          case 'PROJECT': return projects.find(p => p.id === viewState.id)?.name || 'Project';
          case 'TAG': return `# ${viewState.id}`;
          default: return 'Home';
      }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 dark:bg-dark-bg text-slate-900 dark:text-slate-100 transition-colors duration-200 font-sans">
      {/* Header */}
      <header className="h-16 px-4 md:px-8 bg-white/80 dark:bg-dark-surface/80 backdrop-blur-md border-b border-slate-200/60 dark:border-dark-border flex items-center justify-between z-20 sticky top-0">
          <div className="flex items-center gap-4">
            <button 
                onClick={() => setIsMobileOpen(!isMobileOpen)}
                className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors md:hidden text-slate-600 dark:text-slate-300"
            >
                <Menu size={24} />
            </button>
            <div 
                className="flex items-center gap-2 cursor-pointer"
                onClick={() => setViewState({type: 'HOME'})}
            >
                <div className="w-8 h-8 rounded-xl bg-gradient-to-tr from-violet-600 to-indigo-600 flex items-center justify-center text-white shadow-lg shadow-violet-500/30">
                    <span className="font-bold">E</span>
                </div>
                <span className="font-bold text-lg tracking-tight hidden md:block">EchoFlow</span>
            </div>

            <div className="relative ml-4 md:ml-8 hidden md:block group">
                <input 
                    id="header-search"
                    type="text" 
                    placeholder="Search..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className={`
                        bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 placeholder-slate-400 rounded-xl pl-10 pr-4 py-2 text-sm 
                        focus:outline-none focus:ring-2 focus:ring-violet-500/20 focus:bg-white dark:focus:bg-slate-700 w-64 transition-all duration-300
                    `}
                />
                <Search size={16} className="absolute left-3 top-2.5 text-slate-400 pointer-events-none group-focus-within:text-violet-500 transition-colors" />
            </div>
          </div>

          <div className="flex items-center gap-3">
              <button 
                onClick={() => setDarkMode(!darkMode)}
                className="p-2.5 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl transition-colors"
                title="Toggle Theme"
              >
                  {darkMode ? <Sun size={20} /> : <Moon size={20} />}
              </button>
              <button className="hidden md:flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-xl font-semibold text-sm hover:opacity-90 transition-opacity" onClick={() => setShowAddTask(true)}>
                  <Plus size={18} />
                  <span>New</span>
              </button>
              <button className="md:hidden p-2.5 bg-violet-600 text-white rounded-xl shadow-lg shadow-violet-500/30" onClick={() => setShowAddTask(true)}>
                  <Plus size={20} />
              </button>
          </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        <Sidebar 
            currentView={viewState}
            projects={projects}
            onViewChange={(view) => { setViewState(view); setSearchQuery(''); }}
            onAddProject={() => setIsProjectModalOpen(true)}
            isMobileOpen={isMobileOpen}
            onCloseMobile={() => setIsMobileOpen(false)}
        />

        <main className="flex-1 flex flex-col relative w-full h-full overflow-hidden">
            {/* Background Gradients */}
            <div className="absolute top-0 left-0 w-full h-96 bg-gradient-to-b from-violet-50/50 to-transparent dark:from-violet-900/10 pointer-events-none" />

            <div className="flex-1 overflow-y-auto scrollbar-hide z-10">

                {/* Dashboard View */}
                {viewState.type === 'HOME' && !searchQuery ? (
                    <HomeDashboard 
                        items={items}
                        onNavigate={setViewState}
                        onComplete={handleComplete}
                    />
                ) : (
                    /* List View for Tasks/Habits/Projects */
                    <div className="max-w-[800px] mx-auto px-4 md:px-8 pt-8 pb-40">
                        <div className="mb-6 flex items-end justify-between">
                            <div>
