import React from 'react';
import { FlowItem, Priority } from '../types';
import { Flame, Calendar, ArrowRight, CheckCircle2, Trophy, Activity, Wind } from 'lucide-react';

interface HomeDashboardProps {
  items: FlowItem[];
  username?: string;
  onNavigate: (view: any) => void;
  onComplete: (id: string) => void;
}

const HomeDashboard: React.FC<HomeDashboardProps> = ({ items, username = "there", onNavigate, onComplete }) => {
  const today = new Date().toISOString().split('T')[0];

  // Logic for Habits
  const habits = items.filter(i => i.type === 'HABIT');
  const activeHabits = habits.filter(h => !(h.history || []).includes(today)); // Not done today

  // Logic for Tasks (Due today or overdue or P1)
  const urgentTasks = items.filter(i => 
    i.type === 'TASK' && 
    !i.isCompleted && 
    (i.priority === Priority.P1 || (i.dueDate && i.dueDate <= today))
  ).sort((a, b) => (a.priority || 4) - (b.priority || 4));

  // Consistency Graph Logic (Last 14 days)
  const getConsistencyData = () => {
    const dates = [];
    const now = new Date();
    for (let i = 13; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      dates.push(d.toISOString().split('T')[0]);
    }
    return dates.map(date => {
      // Calculate 'intensity' based on habits completed that day
      const completedCount = habits.reduce((acc, habit) => {
        return acc + ((habit.history || []).includes(date) ? 1 : 0);
      }, 0);
      return { date, count: completedCount };
    });
  };

  const consistencyData = getConsistencyData();
  const maxStreak = Math.max(...habits.map(h => h.streak || 0), 0);

  return (
    <div className="p-6 md:p-10 max-w-6xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

      {/* Welcome Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 border-b border-zinc-200 dark:border-dark-border pb-6">
        <div>
          <h1 className="text-3xl font-bold text-zinc-900 dark:text-white tracking-tight">
            Good {new Date().getHours() < 12 ? 'morning' : new Date().getHours() < 18 ? 'afternoon' : 'evening'}, {username}.
          </h1>
          <p className="text-zinc-500 dark:text-zinc-400 mt-2 text-lg">
            Focus is the new productivity.
          </p>
        </div>
        <div className="flex items-center gap-2 text-sm font-medium bg-brand-50 dark:bg-brand-900/10 text-brand-700 dark:text-brand-300 px-4 py-2 rounded-full border border-brand-100 dark:border-brand-900/20">
           <Activity size={16} />
           <span>System: Optimal</span>
        </div>
      </div>

