import React, { useState, useRef, useEffect } from 'react';
import { Check, MoreHorizontal, Calendar, Edit2, Trash2, Tag, Repeat, Clock } from 'lucide-react';
import { FlowItem as FlowItemType, Priority } from '../types';

interface FlowItemProps {
  item: FlowItemType;
  onComplete?: (id: string) => void;
  onDelete: (id: string) => void;
  onUpdate?: (updates: Partial<FlowItemType>) => void;
}

const FlowItem: React.FC<FlowItemProps> = ({ item, onComplete, onDelete, onUpdate }) => {
  const [showMenu, setShowMenu] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(item.content);
  const [editDescription, setEditDescription] = useState(item.description || '');

  const menuRef = useRef<HTMLDivElement>(null);
  const isHabit = item.type === 'HABIT';

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSave = () => {
      if (onUpdate) {
          onUpdate({
              content: editContent,
              description: editDescription
          });
      }
      setIsEditing(false);
  };

  // New Color System
  const priorityColor = {
      [Priority.P1]: 'border-rose-400 bg-rose-50 dark:bg-rose-900/10 text-rose-600',
      [Priority.P2]: 'border-amber-400 bg-amber-50 dark:bg-amber-900/10 text-amber-600',
      [Priority.P3]: 'border-blue-400 bg-blue-50 dark:bg-blue-900/10 text-blue-600',
      [Priority.P4]: 'border-zinc-300 dark:border-zinc-600 bg-white dark:bg-dark-surface text-zinc-500',
  };

  const MenuDropdown = () => (
      <div 
        ref={menuRef}
        className="absolute right-0 top-8 w-40 bg-white dark:bg-dark-surface rounded-xl shadow-lg border border-zinc-100 dark:border-dark-border py-1 z-20 animate-in fade-in zoom-in-95 duration-100"
      >
        <button 
            onClick={(e) => {
                e.stopPropagation();
                setIsEditing(true);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-zinc-700 dark:text-zinc-300 hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight flex items-center gap-2"
        >
            <Edit2 size={14} />
            Edit
        </button>
        <div className="h-px bg-zinc-100 dark:bg-dark-border my-1" />
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onDelete(item.id);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/20 flex items-center gap-2"
        >
            <Trash2 size={14} />
            Delete
        </button>
      </div>
  );

  if (isEditing) {
      return (
          <div className="border border-brand-200 dark:border-brand-900/50 rounded-xl p-4 bg-white dark:bg-dark-surface shadow-md mb-3">
              <input 
                  autoFocus
                  className="w-full text-sm font-semibold text-zinc-800 dark:text-zinc-200 placeholder:text-zinc-400 bg-transparent focus:outline-none mb-2"
                  value={editContent}
                  onChange={e => setEditContent(e.target.value)}
              />
              <textarea 
                  className="w-full text-xs text-zinc-600 dark:text-zinc-400 placeholder:text-zinc-400 bg-transparent focus:outline-none resize-none"
                  rows={2}
                  value={editDescription}
                  onChange={e => setEditDescription(e.target.value)}
                  placeholder="Add details..."
              />
              <div className="flex justify-end gap-2 mt-3 pt-2 border-t border-zinc-100 dark:border-dark-border">
                  <button onClick={() => setIsEditing(false)} className="px-3 py-1.5 text-xs font-semibold text-zinc-600 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight rounded-lg">Cancel</button>
                  <button onClick={handleSave} className="px-3 py-1.5 text-xs font-semibold text-white bg-brand-600 hover:bg-brand-700 rounded-lg">Save</button>
              </div>
          </div>
      );
  }

  return (
    <div className="group relative flex items-center gap-4 p-4 mb-3 bg-white dark:bg-dark-surface border border-zinc-100 dark:border-dark-border rounded-xl shadow-sm hover:shadow-md transition-all duration-200">

        {/* Checkbox */}
        <button
          onClick={(e) => {
              e.stopPropagation();
              onComplete && onComplete(item.id);
          }}
          className={`
            flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300
            ${item.isCompleted 
                ? 'bg-zinc-300 border-zinc-300 dark:bg-zinc-600 dark:border-zinc-600 text-white' 
                : `${priorityColor[item.priority || Priority.P4]} hover:scale-110 bg-transparent`
            }
          `}
        >
          {item.isCompleted && <Check size={14} strokeWidth={3} />}
        </button>

        <div className="flex-1 min-w-0">
           {/* Content */}
           <div className={`text-sm font-medium leading-snug break-words flex items-center gap-2 ${item.isCompleted ? 'line-through text-zinc-400' : 'text-zinc-800 dark:text-zinc-200'}`}>
                {item.content}
                {isHabit && item.streak ? (
                    <span className="text-[10px] font-bold px-1.5 py-0.5 bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-full flex items-center gap-1">
                        🔥 {item.streak}
                    </span>
                ) : null}
           </div>

           {/* Description */}
           {item.description && (
               <div className="text-xs text-zinc-500 dark:text-zinc-400 mt-1 line-clamp-1">
                   {item.description}
               </div>
           )}

           {/* Meta Row */}
           <div className="flex flex-wrap items-center gap-3 mt-2">
               {/* Date */}
               {item.dueDate && (
                   <div className={`flex items-center gap-1 text-[10px] font-medium ${item.dueDate < new Date().toISOString().split('T')[0] ? 'text-rose-500' : 'text-zinc-400'}`}>
                       <Calendar size={10} />
                       <span>{new Date(item.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                   </div>
               )}

               {/* Habit Frequency */}
               {isHabit && item.frequency && (
                   <div className="flex items-center gap-1 text-[10px] text-zinc-400">
                       <Repeat size={10} />
                       <span className="capitalize">{item.frequency}</span>
                   </div>
               )}

               {/* Tags */}
               {item.tags?.map(tag => (
                   <div key={tag} className="flex items-center gap-0.5 text-[10px] bg-zinc-50 dark:bg-dark-surfaceHighlight text-zinc-500 px-1.5 py-0.5 rounded border border-zinc-100 dark:border-zinc-700">
                        <Tag size={8} />
                        {tag}
                   </div>
               ))}
           </div>
        </div>

        {/* Actions (Hidden until hover) */}
        <div className="opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                className="p-2 text-zinc-400 hover:text-zinc-700 dark:hover:text-zinc-200 rounded-lg hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight"
            >
                <MoreHorizontal size={18} />
            </button>
            {showMenu && <MenuDropdown />}
        </div>
    </div>
  );
};

