  // Define the tool for capture
  const captureTool: FunctionDeclaration = {
    name: 'capture_items',
    description: 'Capture tasks, notes, or habits from the user voice input.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        items: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
              content: { type: Type.STRING },
              description: { type: Type.STRING },
              priority: { type: Type.INTEGER },
              dueDate: { type: Type.STRING },
              mood: { type: Type.STRING },
              streak: { type: Type.INTEGER },
              frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
