import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SendHorizontal, Keyboard } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';
import { ProcessedInput } from '../types';
import { processTextEntry } from '../services/geminiService';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isActive, setIsActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const [textInput, setTextInput] = useState('');
  const [statusMessage, setStatusMessage] = useState('Tap to speak');
  const [volume, setVolume] = useState(0); 

  // Refs for Live API management
  const audioContextRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const sessionRef = useRef<any>(null);

  // Tool Definition for Gemini
  const captureTool: FunctionDeclaration = {
    name: 'capture_items',
    description: 'Extracts tasks, habits, and notes from user voice input.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        items: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
              content: { type: Type.STRING, description: "The main text of the item" },
              description: { type: Type.STRING, description: "Any additional details mentioned" },
              priority: { type: Type.INTEGER, description: "1 (High) to 4 (Low)" },
              dueDate: { type: Type.STRING, description: "YYYY-MM-DD format if mentioned" },
              streak: { type: Type.INTEGER },
              frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["type", "content"]
          }
        }
      },
      required: ['items']
    }
  };

  // --- Audio Encoding Helpers ---
  const encodeAudio = (inputData: Float32Array): string => {
    const l = inputData.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      // Clamp and convert float (-1 to 1) to int16
      const s = Math.max(-1, Math.min(1, inputData[i]));
      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }

    // Convert buffer to binary string then btoa
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return window.btoa(binary);
  };


  const startLiveSession = async () => {
    try {
      setStatusMessage("Connecting...");

      // 1. Setup Audio Input (Force 16kHz for compatibility)
      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
          channelCount: 1,
          sampleRate: 16000,
          echoCancellation: true
        }
      });
      streamRef.current = stream;

      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = audioContext;

      const source = audioContext.createMediaStreamSource(stream);
      const processor = audioContext.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;

      source.connect(processor);
      processor.connect(audioContext.destination);

      // 2. Connect to Gemini Live
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [captureTool] }],
          // CRITICAL UPDATE: Encouraging immediate capture
          systemInstruction: `
            You are a real-time productivity assistant. 
            Your goal is to capture tasks, habits, and notes INSTANTLY as the user speaks. 
            Do not wait for the user to stop speaking. 
            If the user lists items (e.g., "Buy milk, then walk the dog"), call the 'capture_items' tool immediately after "Buy milk" is detected, and again after "walk the dog" is detected. 
            Do not buffer multiple items if they are distinct commands. Be extremely proactive.
            Respond with brief audio confirmations like "Added" or "Got it" after capturing.
          `,
        },
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setStatusMessage("Listening...");
          },
          onmessage: (msg: LiveServerMessage) => {
            // Check for Function Calls (The Classification Result)
            if (msg.toolCall) {
              msg.toolCall.functionCalls.forEach(fc => {
                if (fc.name === 'capture_items') {
                  const args = fc.args as unknown as ProcessedInput;
                  onProcessed(args);

                  // Must send response back to keep session healthy
                  sessionPromise.then(session => {
                    session.sendToolResponse({
                      functionResponses: {
                        id: fc.id,
                        name: fc.name,
                        response: { result: "Success" }
                      }
                    });
                  });
                }
              });
            }
          },
          onclose: () => {
            setIsActive(false);
            setStatusMessage("Tap to speak");
          },
          onerror: (err) => {
            console.error("Live API Error", err);
            stopLiveSession();
            setStatusMessage("Connection Error");
          }
        }
      });

      // 3. Stream Audio Data
      processor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);

        // Visualizer volume calculation
        let sum = 0;
        for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
        setVolume(Math.sqrt(sum / inputData.length));

        const base64Data = encodeAudio(inputData);

        // Send to Gemini
        sessionPromise.then(session => {
          sessionRef.current = session;
          session.sendRealtimeInput({
            media: {
              mimeType: 'audio/pcm;rate=16000',
              data: base64Data
            }
          });
        });
      };

    } catch (err) {
      console.error("Failed to start live session", err);
      setIsActive(false);
      setStatusMessage("Mic access denied");
    }
  };

  const stopLiveSession = () => {
    // Cleanup Audio
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }

    // Reset State
    setIsActive(false);
    setStatusMessage("Tap to speak");
    setVolume(0);
    sessionRef.current = null;
  };

  const toggleSession = () => {
    if (isActive) {
      stopLiveSession();
    } else {
      startLiveSession();
    }
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!textInput.trim()) return;

    setIsProcessing(true);
    setStatusMessage("Processing...");
    try {
        const result = await processTextEntry(textInput);
        if (result) onProcessed(result);
        setTextInput('');
        setShowTextInput(false);
        setStatusMessage("Tap to speak");
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-[260px] right-0 p-6 flex flex-col items-center justify-end z-20 pointer-events-none">

       {/* Active State Visualizer */}
       {isActive && (
           <div className="pointer-events-auto mb-6 bg-zinc-900/95 backdrop-blur-xl text-white px-8 py-6 rounded-3xl shadow-2xl flex flex-col items-center gap-4 animate-in slide-in-from-bottom-10 fade-in duration-300 border border-zinc-800">
               <div className="flex items-center gap-3">
                   <div className="relative flex items-center justify-center w-4 h-4">
                       <span className="absolute w-full h-full rounded-full bg-emerald-500 animate-ping opacity-75"></span>
                       <span className="relative w-2.5 h-2.5 rounded-full bg-emerald-500"></span>
                   </div>
                   <span className="text-sm font-medium tracking-wide uppercase text-emerald-400">EchoFlow Live</span>
               </div>

               {/* Dynamic Audio Bars */}
               <div className="flex items-center gap-1.5 h-12 justify-center">
                   {[...Array(5)].map((_, i) => (
                       <div 
                           key={i}
                           className="w-2 bg-gradient-to-t from-emerald-500 to-emerald-300 rounded-full transition-all duration-75"
                           style={{ 
                               height: `${Math.max(15, Math.min(100, volume * 800 * (Math.random() + 0.5)))}%`,
                               opacity: 0.8 
                           }}
                       />
                   ))}
               </div>
               <p className="text-xs text-zinc-400 font-medium">Listening...</p>
           </div>
       )}

       {/* Text Input Overlay */}
       {showTextInput && (
           <div className="pointer-events-auto w-full max-w-2xl mb-4 bg-white dark:bg-dark-surface rounded-2xl shadow-xl border border-zinc-200 dark:border-dark-border p-2 animate-in slide-in-from-bottom-5">
               <form onSubmit={handleTextSubmit} className="flex gap-2">
                   <input 
                      autoFocus
                      className="flex-1 px-4 py-3 bg-transparent outline-none text-zinc-800 dark:text-zinc-200 placeholder:text-zinc-400"
                      placeholder="Type your thought..."
                      value={textInput}
                      onChange={e => setTextInput(e.target.value)}
                      disabled={isProcessing}
                   />
                   <button 
                      type="submit" 
                      disabled={isProcessing || !textInput.trim()}
                      className="p-3 bg-brand-600 text-white rounded-xl hover:bg-brand-700 transition-colors disabled:opacity-50"
                   >
                       {isProcessing ? <Loader2 className="animate-spin" size={20}/> : <SendHorizontal size={20}/>}
                   </button>
               </form>
           </div>
       )}

      <div className="pointer-events-auto flex items-center gap-4 transition-all duration-300">
        <button 
            onClick={() => setShowTextInput(!showTextInput)}
            className="bg-white dark:bg-dark-surface text-zinc-500 dark:text-zinc-400 p-3 rounded-full shadow-lg border border-zinc-100 dark:border-dark-border hover:text-brand-600 dark:hover:text-brand-400 transition-colors"
        >
            <Keyboard size={20} />
        </button>

        <button
            onClick={toggleSession}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-xl transition-all duration-300
            ${isActive 
                ? 'bg-zinc-800 text-emerald-400 ring-4 ring-emerald-500/20 scale-110' 
                : isProcessing 
                    ? 'bg-zinc-100 dark:bg-dark-surface text-zinc-400' 
                    : 'bg-brand-600 text-white hover:bg-brand-700 hover:scale-105 shadow-brand-500/30'
            }
            `}
        >
            {isProcessing ? (
                <Loader2 size={24} className="animate-spin" />
            ) : isActive ? (
                <Square size={20} fill="currentColor" />
            ) : (
                <div className="relative">
                    <Mic size={28} />
                    <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-emerald-400 rounded-full border-2 border-brand-600" title="Live Ready"></div>
                </div>
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-zinc-400 dark:text-zinc-500 text-center transition-opacity duration-300">
        {statusMessage}
      </div>
    </div>
  );
};

