        contents: `Analyze this input for EchoFlow: "${text}". Current time: ${now}. Classify into tasks, notes, or habits. For habits, detect frequency (daily, weekly, monthly).`,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    items: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
                                content: { type: Type.STRING },
                                description: { type: Type.STRING },
                                priority: { type: Type.INTEGER },
                                dueDate: { type: Type.STRING },
                                mood: { type: Type.STRING },
                                streak: { type: Type.INTEGER },
                                frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
                                tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                            },
                            required: ["type", "content"]
                        }
                    }
                }
            }
        }
      });
      return response.text ? JSON.parse(response.text) : null;
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!textInput.trim()) return;

    setIsProcessing(true);
    setStatusMessage("Processing...");
    try {
        const result = await processTextEntry(textInput);
