import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, GripVertical } from 'lucide-react';
import { FlowItem, Project, Priority } from '../types';

interface CalendarViewProps {
  items: FlowItem[];
  projects: Project[];
  onMoveTask: (taskId: string, newDate: string) => void;
  onComplete: (id: string) => void;
}

const CalendarView: React.FC<CalendarViewProps> = ({ items, projects, onMoveTask, onComplete }) => {
  const [currentDate, setCurrentDate] = useState(new Date());

  // Calendar Logic
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = new Date(year, month, 1).getDay(); // 0 = Sun

  const prevMonthDays = new Date(year, month, 0).getDate();

  const dates: { day: number; isCurrentMonth: boolean; dateString: string }[] = [];

  // Previous month filler
  for (let i = firstDayOfMonth - 1; i >= 0; i--) {
    const d = prevMonthDays - i;
    const dateStr = new Date(year, month - 1, d + 1).toISOString().split('T')[0]; // +1 adjustment to fix timezone offset issues simply
    // Better way to generate YYYY-MM-DD locally
    const prevDate = new Date(year, month - 1, d);
    dates.push({ 
        day: d, 
        isCurrentMonth: false,
        dateString: formatDate(prevDate)
    });
  }

  // Current month
  for (let i = 1; i <= daysInMonth; i++) {
    const date = new Date(year, month, i);
    dates.push({ 
        day: i, 
        isCurrentMonth: true,
        dateString: formatDate(date)
    });
  }

  // Next month filler (to 42 cells grid)
  const remainingCells = 42 - dates.length;
  for (let i = 1; i <= remainingCells; i++) {
    const date = new Date(year, month + 1, i);
    dates.push({ 
        day: i, 
        isCurrentMonth: false, 
        dateString: formatDate(date)
    });
  }

  function formatDate(d: Date) {
      const y = d.getFullYear();
      const m = String(d.getMonth() + 1).padStart(2, '0');
      const day = String(d.getDate()).padStart(2, '0');
      return `${y}-${m}-${day}`;
  }

  const changeMonth = (delta: number) => {
    setCurrentDate(new Date(year, month + delta, 1));
  };

  const todayStr = formatDate(new Date());

  // Drag and Drop Handlers
  const handleDragStart = (e: React.DragEvent, taskId: string) => {
    e.dataTransfer.setData('taskId', taskId);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault(); // Necessary to allow dropping
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, dateStr: string) => {
    e.preventDefault();
    const taskId = e.dataTransfer.getData('taskId');
    if (taskId) {
        onMoveTask(taskId, dateStr);
    }
  };

  return (
    <div className="h-full flex flex-col p-6 animate-in fade-in duration-500">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-zinc-800 dark:text-zinc-100 flex items-center gap-2">
            {currentDate.toLocaleString('default', { month: 'long', year: 'numeric' })}
        </h2>
        <div className="flex items-center gap-2">
            <button onClick={() => setCurrentDate(new Date())} className="px-3 py-1.5 text-sm font-medium bg-zinc-100 dark:bg-dark-surfaceHighlight rounded-lg hover:bg-zinc-200 transition-colors mr-2">
                Today
            </button>
            <button onClick={() => changeMonth(-1)} className="p-2 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight rounded-full">
                <ChevronLeft size={20} />
            </button>
            <button onClick={() => changeMonth(1)} className="p-2 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight rounded-full">
                <ChevronRight size={20} />
            </button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-px bg-zinc-200 dark:bg-zinc-800 border border-zinc-200 dark:border-zinc-800 rounded-lg overflow-hidden flex-1 shadow-sm">
        {/* Headers */}
        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
            <div key={day} className="bg-zinc-50 dark:bg-dark-surface p-2 text-center text-xs font-semibold text-zinc-500 uppercase tracking-wide">
                {day}
            </div>
        ))}

        {/* Calendar Cells */}
        {dates.map((d, index) => {
            const tasksForDay = items.filter(item => 
                item.dueDate === d.dateString && !item.isCompleted
            );

            return (
                <div 
                    key={index}
                    onDragOver={handleDragOver}
                    onDrop={(e) => handleDrop(e, d.dateString)}
                    className={`
                        bg-white dark:bg-dark-surface p-2 min-h-[100px] flex flex-col gap-1 transition-colors
                        ${!d.isCurrentMonth ? 'bg-zinc-50/50 dark:bg-dark-surface/50 text-zinc-400' : ''}
                        ${d.dateString === todayStr ? 'bg-brand-50/30 dark:bg-brand-900/10' : ''}
                        hover:bg-zinc-50 dark:hover:bg-zinc-800/50
                    `}
                >
                    <div className={`text-xs font-medium mb-1 ${d.dateString === todayStr ? 'text-brand-600 dark:text-brand-400' : 'text-zinc-500'}`}>
                        {d.day}
                    </div>

                    <div className="flex-1 overflow-y-auto scrollbar-hide space-y-1">
                        {tasksForDay.map(task => {
                            const project = projects.find(p => p.id === task.projectId);
                            const priorityColor = {
                                [Priority.P1]: 'border-rose-400 bg-rose-50 dark:bg-rose-900/20',
                                [Priority.P2]: 'border-amber-400 bg-amber-50 dark:bg-amber-900/20',
                                [Priority.P3]: 'border-blue-400 bg-blue-50 dark:bg-blue-900/20',
                                [Priority.P4]: 'border-zinc-200 bg-white dark:bg-dark-surfaceHighlight',
                            }[task.priority || Priority.P4];

                            return (
                                <div 
                                    key={task.id}
                                    draggable
                                    onDragStart={(e) => handleDragStart(e, task.id)}
                                    className={`
                                        group text-[10px] p-1.5 rounded border-l-2 shadow-sm cursor-move select-none
                                        ${priorityColor} dark:border-l-4
                                    `}
                                >
                                    <div className="flex items-start gap-1">
                                        <button 
                                            onClick={() => onComplete(task.id)}
                                            className="mt-0.5 w-2.5 h-2.5 rounded-full border border-zinc-400 hover:bg-zinc-400 dark:border-zinc-500 transition-colors"
                                        />
                                        <span className="truncate leading-tight flex-1 text-zinc-700 dark:text-zinc-200">
                                            {task.content}
                                        </span>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            );
        })}
      </div>
    </div>
  );
};

