import React, { useState, useRef, useEffect } from 'react';
import { Check, MoreHorizontal, Calendar, Edit2, Trash2, Tag, Repeat } from 'lucide-react';
import { FlowItem as FlowItemType, Priority } from '../types';

interface FlowItemProps {
  item: FlowItemType;
  onComplete?: (id: string) => void;
  onDelete: (id: string) => void;
  onUpdate?: (updates: Partial<FlowItemType>) => void;
}

const FlowItem: React.FC<FlowItemProps> = ({ item, onComplete, onDelete, onUpdate }) => {
  const [showMenu, setShowMenu] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editContent, setEditContent] = useState(item.content);
  const [editDescription, setEditDescription] = useState(item.description || '');

  const menuRef = useRef<HTMLDivElement>(null);
  const isHabit = item.type === 'HABIT';

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setShowMenu(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSave = () => {
      if (onUpdate) {
          onUpdate({
              content: editContent,
              description: editDescription
          });
      }
      setIsEditing(false);
  };

  const priorityColor = {
      [Priority.P1]: 'border-rose-400 bg-rose-50 dark:bg-rose-900/10 text-rose-600',
      [Priority.P2]: 'border-amber-400 bg-amber-50 dark:bg-amber-900/10 text-amber-600',
      [Priority.P3]: 'border-blue-400 bg-blue-50 dark:bg-blue-900/10 text-blue-600',
      [Priority.P4]: 'border-zinc-300 dark:border-zinc-600 bg-white dark:bg-dark-surface text-zinc-500',
  };

  const MenuDropdown = () => (
      <div 
        ref={menuRef}
        className="absolute right-0 top-8 w-40 bg-white dark:bg-dark-surface rounded-xl shadow-lg border border-zinc-100 dark:border-dark-border py-1 z-20 animate-in fade-in zoom-in-95 duration-100"
      >
        <button 
            onClick={(e) => {
                e.stopPropagation();
                setIsEditing(true);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-zinc-700 dark:text-zinc-300 hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight flex items-center gap-2"
        >
            <Edit2 size={14} />
            Edit
        </button>
        <div className="h-px bg-zinc-100 dark:bg-dark-border my-1" />
        <button 
            onClick={(e) => {
                e.stopPropagation();
                onDelete(item.id);
                setShowMenu(false);
            }}
            className="w-full text-left px-3 py-2 text-sm text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/20 flex items-center gap-2"
        >
            <Trash2 size={14} />
            Delete
        </button>
      </div>
  );

  if (isEditing) {
      return (
          <div className="border border-brand-200 dark:border-brand-900/50 rounded-xl p-4 bg-white dark:bg-dark-surface shadow-md mb-3">
              <input 
                  autoFocus
                  className="w-full text-sm font-semibold text-zinc-800 dark:text-zinc-200 placeholder:text-zinc-400 bg-transparent focus:outline-none mb-2"
                  value={editContent}
                  onChange={e => setEditContent(e.target.value)}
              />
              <textarea 
                  className="w-full text-xs text-zinc-600 dark:text-zinc-400 placeholder:text-zinc-400 bg-transparent focus:outline-none resize-none"
                  rows={2}
                  value={editDescription}
                  onChange={e => setEditDescription(e.target.value)}
                  placeholder="Add details..."
              />
              <div className="flex justify-end gap-2 mt-3 pt-2 border-t border-zinc-100 dark:border-dark-border">
                  <button onClick={() => setIsEditing(false)} className="px-3 py-1.5 text-xs font-semibold text-zinc-600 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight rounded-lg">Cancel</button>
                  <button onClick={handleSave} className="px-3 py-1.5 text-xs font-semibold text-white bg-brand-600 hover:bg-brand-700 rounded-lg">Save</button>
              </div>
          </div>
      );
  }

  return (
    <div className="group relative flex items-center gap-4 p-4 mb-3 bg-white dark:bg-dark-surface border border-zinc-100 dark:border-dark-border rounded-xl shadow-sm hover:shadow-md transition-all duration-200">

        {/* Checkbox */}
        <button
          onClick={(e) => {
              e.stopPropagation();
              onComplete && onComplete(item.id);
          }}
          className={`
            flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300
            ${item.isCompleted 
                ? 'bg-zinc-300 border-zinc-300 dark:bg-zinc-600 dark:border-zinc-600 text-white scale-90' 
                : `${priorityColor[item.priority || Priority.P4]} hover:scale-110 bg-transparent`
            }
          `}
        >
          {item.isCompleted && <Check size={14} strokeWidth={3} className="animate-in zoom-in duration-200" />}
        </button>

        <div className="flex-1 min-w-0">
           {/* Content with Smooth Strikethrough Animation */}
           <div className="relative">
                <div 
                    className={`text-sm font-medium leading-snug break-words flex items-center gap-2 transition-all duration-500 ${
                        item.isCompleted ? 'text-zinc-400 dark:text-zinc-500' : 'text-zinc-800 dark:text-zinc-200'
                    }`}
                >
                        {item.content}
                        {isHabit && item.streak ? (
                            <span className="text-[10px] font-bold px-1.5 py-0.5 bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-full flex items-center gap-1">
                                🔥 {item.streak}
                            </span>
                        ) : null}
                </div>
                {/* Strikethrough Line Animation */}
                <div 
                    className={`absolute top-1/2 left-0 h-[2px] bg-zinc-400 dark:bg-zinc-500 rounded-full transition-all duration-500 ease-in-out pointer-events-none ${
                        item.isCompleted ? 'w-full opacity-100' : 'w-0 opacity-0'
                    }`}
                />
           </div>

           {/* Description */}
           {item.description && (
               <div className={`text-xs mt-1 line-clamp-1 transition-colors duration-300 ${item.isCompleted ? 'text-zinc-300 dark:text-zinc-600' : 'text-zinc-500 dark:text-zinc-400'}`}>
                   {item.description}
               </div>
           )}

           {/* Meta Row */}
           <div className={`flex flex-wrap items-center gap-3 mt-2 transition-opacity duration-300 ${item.isCompleted ? 'opacity-50' : 'opacity-100'}`}>
               {/* Date */}
               {item.dueDate && (
                   <div className={`flex items-center gap-1 text-[10px] font-medium ${item.dueDate < new Date().toISOString().split('T')[0] && !item.isCompleted ? 'text-rose-500' : 'text-zinc-400'}`}>
                       <Calendar size={10} />
                       <span>{new Date(item.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}</span>
                   </div>
               )}

               {/* Habit Frequency */}
               {isHabit && item.frequency && (
                   <div className="flex items-center gap-1 text-[10px] text-zinc-400">
                       <Repeat size={10} />
                       <span className="capitalize">{item.frequency}</span>
                   </div>
               )}

               {/* Tags */}
               {item.tags?.map(tag => (
                   <div key={tag} className="flex items-center gap-0.5 text-[10px] bg-zinc-50 dark:bg-dark-surfaceHighlight text-zinc-500 px-1.5 py-0.5 rounded border border-zinc-100 dark:border-zinc-700">
                        <Tag size={8} />
                        {tag}
                   </div>
               ))}
           </div>
        </div>

        {/* Actions (Hidden until hover) */}
        <div className="opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={(e) => { e.stopPropagation(); setShowMenu(!showMenu); }}
                className="p-2 text-zinc-400 hover:text-zinc-700 dark:hover:text-zinc-200 rounded-lg hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight"
            >
                <MoreHorizontal size={18} />
            </button>
            {showMenu && <MenuDropdown />}
        </div>
    </div>
  );
};

export default FlowItem;

import React, { useState, useRef, useEffect } from 'react';
import { Calendar, Flag, Hash, Sparkles, X, Loader2 } from 'lucide-react';
import { Priority, Project } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

interface AddTaskProps {
  projects: Project[];
  defaultProjectId: string;
  onAddTask: (task: { content: string; description?: string; priority: Priority; projectId: string; dueDate?: string }) => void;
  onCancel: () => void;
}

const AddTask: React.FC<AddTaskProps> = ({ projects, defaultProjectId, onAddTask, onCancel }) => {
  const [content, setContent] = useState('');
  const [description, setDescription] = useState('');
  const [priority, setPriority] = useState<Priority>(Priority.P4);
  const [projectId, setProjectId] = useState<string>(defaultProjectId);
  const [dueDate, setDueDate] = useState<string>('');

  const [isAiProcessing, setIsAiProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!content.trim()) return;

    onAddTask({
      content,
      description: description.trim() || undefined,
      priority,
      projectId,
      dueDate: dueDate || undefined
    });
    setContent('');
    setDescription('');
  };

  const handleSmartAdd = async () => {
      if (!content.trim()) return;
      setIsAiProcessing(true);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
        const now = new Date().toISOString();
        const response = await ai.models.generateContent({
          model: "gemini-2.5-flash", // Replaced Gemini 3 for better latency/availability
          contents: `
            You are a smart task parser.
            Current Time: ${now}
            Projects: ${JSON.stringify(projects.map(p => p.name))}

            Input: "${content}"

            Extract:
            - content: clear task title
            - description: extra details
            - priority: 1 (Urgent) to 4 (Low). Default 4.
            - dueDate: YYYY-MM-DD
            - projectName: Exact match from provided list if applicable
          `,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                content: { type: Type.STRING },
                description: { type: Type.STRING },
                priority: { type: Type.INTEGER },
                dueDate: { type: Type.STRING },
                projectName: { type: Type.STRING }
              },
              required: ["content"]
            }
          }
        });

        const result = response.text ? JSON.parse(response.text) : null;
        if (result) {
            setContent(result.content);
            if (result.description) setDescription(result.description);
            if (result.priority) setPriority(result.priority);
            if (result.dueDate) setDueDate(result.dueDate);
            if (result.projectName) {
                const found = projects.find(p => p.name.toLowerCase() === result.projectName.toLowerCase());
                if (found) setProjectId(found.id);
            }
        }
      } catch (e) {
          console.error("AI parse failed", e);
      } finally {
          setIsAiProcessing(false);
      }
  };

  const priorityColors = {
    [Priority.P1]: 'text-rose-500',
    [Priority.P2]: 'text-amber-500',
    [Priority.P3]: 'text-blue-500',
    [Priority.P4]: 'text-zinc-500',
  };

  return (
    <div className="border border-brand-200 dark:border-brand-900/50 rounded-2xl p-4 bg-white dark:bg-dark-surface shadow-xl shadow-brand-500/5 mb-6 transition-all relative z-10 animate-in fade-in slide-in-from-top-4">
      <form onSubmit={handleSubmit}>
        <div className="mb-4">
            <div className="flex items-center gap-2">
              <input
                ref={inputRef}
                type="text"
                placeholder="What's on your mind?"
                className="w-full text-lg font-semibold text-zinc-800 dark:text-zinc-100 placeholder:text-zinc-300 dark:placeholder:text-zinc-600 focus:outline-none bg-transparent mb-2"
                value={content}
                onChange={(e) => setContent(e.target.value)}
                disabled={isAiProcessing}
              />
              {content.length > 3 && (
                  <button 
                    type="button" 
                    onClick={handleSmartAdd}
                    className="text-brand-500 hover:text-brand-600 transition-colors p-1"
                    title="Smart Parse with AI"
                  >
                      {isAiProcessing ? <Loader2 size={20} className="animate-spin" /> : <Sparkles size={20} />}
                  </button>
              )}
            </div>
          <textarea
            placeholder="Description (optional)"
            rows={2}
            className="w-full text-sm text-zinc-600 dark:text-zinc-400 placeholder:text-zinc-300 dark:placeholder:text-zinc-600 focus:outline-none resize-none bg-transparent"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            disabled={isAiProcessing}
          />
        </div>

        <div className="flex items-center gap-3 mb-4 flex-wrap">
            {/* Due Date */}
            <button 
                type="button" 
                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border text-xs font-medium transition-colors ${dueDate ? 'bg-green-50 border-green-200 text-green-700 dark:bg-green-900/20 dark:border-green-800 dark:text-green-400' : 'border-zinc-200 dark:border-dark-border text-zinc-500 hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight'}`}
                onClick={() => {
                    const tomorrow = new Date();
                    tomorrow.setDate(tomorrow.getDate() + 1);
                    setDueDate(dueDate ? '' : tomorrow.toISOString().split('T')[0]);
                }}
            >
              <Calendar size={14} />
              {dueDate ? 'Tomorrow' : 'Set Due Date'}
            </button>

            {/* Priority */}
            <div className="relative group">
                <button type="button" className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-zinc-200 dark:border-dark-border text-xs font-medium hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight transition-colors ${priority !== Priority.P4 ? priorityColors[priority] : 'text-zinc-500'}`}>
                    <Flag size={14} fill={priority === Priority.P4 ? 'none' : 'currentColor'} />
                    Priority
                </button>
                <div className="absolute top-full left-0 mt-2 w-32 bg-white dark:bg-dark-surface border border-zinc-100 dark:border-dark-border rounded-xl shadow-xl hidden group-hover:block z-50 py-1">
                    {[Priority.P1, Priority.P2, Priority.P3, Priority.P4].map(p => (
                        <div key={p} onClick={() => setPriority(p)} className="flex items-center gap-2 px-3 py-2 hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight cursor-pointer text-xs text-zinc-700 dark:text-zinc-300">
                             <Flag size={14} className={priorityColors[p]} fill={p === Priority.P4 ? 'none' : 'currentColor'}/> 
                             Priority {p}
                        </div>
                    ))}
                </div>
            </div>

            {/* Project Selector */}
            <div className="relative group">
                <button type="button" className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg border border-zinc-200 dark:border-dark-border text-xs font-medium hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight text-zinc-500 transition-colors">
                    <Hash size={14} />
                    {projects.find(p => p.id === projectId)?.name || 'Inbox'}
                </button>
                 <div className="absolute top-full left-0 mt-2 w-48 max-h-48 overflow-y-auto scrollbar-hide bg-white dark:bg-dark-surface border border-zinc-100 dark:border-dark-border rounded-xl shadow-xl hidden group-hover:block z-50">
                    <div onClick={() => setProjectId('inbox')} className="px-3 py-2 hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight cursor-pointer text-xs truncate flex items-center gap-2 text-zinc-700 dark:text-zinc-300">
                        <Hash size={14} className="text-zinc-400" /> Inbox
                    </div>
                    {projects.map(p => (
                        <div key={p.id} onClick={() => setProjectId(p.id)} className="px-3 py-2 hover:bg-zinc-50 dark:hover:bg-dark-surfaceHighlight cursor-pointer text-xs truncate flex items-center gap-2 text-zinc-700 dark:text-zinc-300">
                            <span className="w-2 h-2 rounded-full flex-shrink-0" style={{backgroundColor: p.color}}></span>
                            {p.name}
                        </div>
                    ))}
                </div>
            </div>
        </div>

        <div className="flex items-center justify-end gap-3 pt-4 border-t border-zinc-100 dark:border-dark-border">
            <button
              type="button"
              onClick={onCancel}
              className="px-4 py-2 rounded-lg text-sm font-semibold text-zinc-500 hover:text-zinc-800 dark:hover:text-zinc-200 hover:bg-zinc-100 dark:hover:bg-dark-surfaceHighlight transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={!content.trim() || isAiProcessing}
              className={`px-6 py-2 rounded-lg text-sm font-semibold text-white transition-all shadow-lg shadow-brand-500/30 ${!content.trim() ? 'bg-zinc-300 dark:bg-zinc-700 cursor-not-allowed shadow-none' : 'bg-brand-600 hover:bg-brand-700 hover:scale-105'}`}
            >
              Add to Flow
            </button>
        </div>
      </form>
    </div>
  );
};

export default AddTask;

import React, { useState } from 'react';
import { Check, Calendar, MoreHorizontal, MessageSquareText } from 'lucide-react';
import { Task, Priority } from '../types';
import { GoogleGenAI, Type } from '@google/genai';

interface TaskItemProps {
  task: Task;
  onComplete: (id: string) => void;
  onUpdate: (task: Task) => void;
  onDelete: (id: string) => void;
}

const TaskItem: React.FC<TaskItemProps> = ({ task, onComplete, onUpdate, onDelete }) => {
  const [isHovered, setIsHovered] = useState(false);
  const [isSuggesting, setIsSuggesting] = useState(false);

  const priorityBorderColor = {
    [Priority.P1]: 'border-red-500 bg-red-50',
    [Priority.P2]: 'border-orange-500 bg-orange-50',
    [Priority.P3]: 'border-blue-500 bg-blue-50',
    [Priority.P4]: 'border-gray-300 hover:border-gray-400',
  };

  const handleSuggest = async () => {
    setIsSuggesting(true);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash", // Replaced Gemini 3
            contents: `List 3-5 subtasks for: "${task.content}"`,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
                }
            }
        });

        const suggestions: string[] = response.text ? JSON.parse(response.text) : [];

        if (suggestions.length > 0) {
            const newDesc = (task.description ? task.description + '\n\n' : '') + "AI Suggestions:\n- " + suggestions.join('\n- ');
            onUpdate({ ...task, description: newDesc });
        }
    } catch (e) {
        console.error("Failed to suggest", e);
    } finally {
        setIsSuggesting(false);
    }
  };

  return (
    <div 
      className="group flex items-start gap-3 py-3 border-b border-gray-100 last:border-0 hover:bg-gray-50 -mx-2 px-2 rounded-md transition-colors cursor-pointer"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <button
        onClick={() => onComplete(task.id)}
        className={`mt-0.5 flex-shrink-0 w-5 h-5 rounded-full border flex items-center justify-center transition-colors ${priorityBorderColor[task.priority]} group/check`}
      >
        <Check size={12} className="opacity-0 group-hover/check:opacity-100 text-gray-600" />
      </button>

      <div className="flex-grow min-w-0">
        <div className="flex items-start justify-between">
            <div className="text-sm text-gray-800 leading-tight">
                {task.content}
            </div>
        </div>

        {task.description && (
          <div className="text-xs text-gray-500 mt-1 line-clamp-2 whitespace-pre-wrap">
            {task.description}
          </div>
        )}

        <div className="flex items-center gap-3 mt-1.5">
          {task.dueDate && (
            <div className="flex items-center gap-1 text-xs text-red-600">
              <Calendar size={12} />
              <span>{task.dueDate}</span>
            </div>
          )}
        </div>
      </div>

      <div className={`flex items-center gap-1 opacity-0 ${isHovered ? 'opacity-100' : ''} transition-opacity`}>
         <button 
            onClick={(e) => { e.stopPropagation(); handleSuggest(); }}
            className="p-1 text-gray-400 hover:text-purple-600 rounded"
            title="Get AI subtask suggestions"
            disabled={isSuggesting}
         >
             {isSuggesting ? (
                 <div className="w-4 h-4 border-2 border-purple-500 rounded-full border-t-transparent animate-spin"></div>
             ) : (
                <MessageSquareText size={16} />
             )}
         </button>
         <button 
            onClick={(e) => { e.stopPropagation(); onDelete(task.id); }}
            className="p-1 text-gray-400 hover:text-red-600 rounded"
            title="Delete task"
         >
             <MoreHorizontal size={16} />
         </button>
      </div>
    </div>
  );
};

export default TaskItem;

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, SendHorizontal, Keyboard, Radio } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from '@google/genai';
import { ProcessedInput } from '../types';

interface VoiceCaptureProps {
  onProcessed: (result: ProcessedInput) => void;
}

const VoiceCapture: React.FC<VoiceCaptureProps> = ({ onProcessed }) => {
  const [isActive, setIsActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showTextInput, setShowTextInput] = useState(false);
  const [textInput, setTextInput] = useState('');
  const [statusMessage, setStatusMessage] = useState('Say "Hey Echo"');
  const [volume, setVolume] = useState(0); 
  const [isWakeWordListening, setIsWakeWordListening] = useState(false);

  // Refs for Live API management
  const audioContextRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const sessionRef = useRef<any>(null);
  const mountedRef = useRef(true);

  // Wake Word Ref
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    mountedRef.current = true;
    // Initialize Wake Word Listener on Mount
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        const recognition = new SpeechRecognition();
        recognition.continuous = true;
        recognition.interimResults = true;
        recognition.lang = 'en-US';

        recognition.onresult = (event: any) => {
            const results = event.results;
            const transcript = results[results.length - 1][0].transcript.toLowerCase().trim();

            if (transcript.includes('echo') && !isActive && !sessionRef.current) {
                // Debounce/Check if already activating
                recognition.stop();
                setIsWakeWordListening(false);
                setStatusMessage("Activating...");
                // Small delay to release mic
                setTimeout(() => startLiveSession(), 100);
            }
        };

        recognition.onend = () => {
            // Auto-restart if we aren't in an active session and component is mounted
            if (!sessionRef.current && !isActive && mountedRef.current) {
                try {
                    recognition.start();
                    setIsWakeWordListening(true);
                } catch (e) {
                    // Ignore start errors
                }
            } else {
                setIsWakeWordListening(false);
            }
        };

        recognitionRef.current = recognition;
        try {
            recognition.start();
            setIsWakeWordListening(true);
        } catch (e) {
            console.error("Wake word start error", e);
        }
    }

    return () => {
        mountedRef.current = false;
        if (recognitionRef.current) recognitionRef.current.stop();
        stopLiveSession();
    };
  }, []); // Run once on mount

  // Tool Definition for Gemini
  const captureTool: FunctionDeclaration = {
    name: 'capture_items',
    description: 'Extracts tasks, habits, and notes from user voice input.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        items: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
              content: { type: Type.STRING, description: "The main text of the item" },
              description: { type: Type.STRING, description: "Any additional details mentioned" },
              priority: { type: Type.INTEGER, description: "1 (High) to 4 (Low)" },
              dueDate: { type: Type.STRING, description: "YYYY-MM-DD format if mentioned" },
              streak: { type: Type.INTEGER },
              frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
              tags: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["type", "content"]
          }
        }
      },
      required: ['items']
    }
  };

  // --- Audio Encoding Helpers ---
  const encodeAudio = (inputData: Float32Array): string => {
    const l = inputData.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      const s = Math.max(-1, Math.min(1, inputData[i]));
      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }

    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return window.btoa(binary);
  };


  const startLiveSession = async () => {
    // Stop wake word listener if running
    if (recognitionRef.current) recognitionRef.current.stop();

    try {
      setStatusMessage("Connecting...");

      const stream = await navigator.mediaDevices.getUserMedia({ 
        audio: {
          channelCount: 1,
          sampleRate: 16000,
          echoCancellation: true
        }
      });
      streamRef.current = stream;

      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = audioContext;

      const source = audioContext.createMediaStreamSource(stream);
      const processor = audioContext.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;

      source.connect(processor);
      processor.connect(audioContext.destination);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [captureTool] }],
          systemInstruction: `
            You are a real-time productivity assistant. 
            Your goal is to capture tasks, habits, and notes INSTANTLY as the user speaks. 
            Do not wait for the user to stop speaking. 
            If the user lists items (e.g., "Buy milk, then walk the dog"), call the 'capture_items' tool immediately after "Buy milk" is detected, and again after "walk the dog" is detected. 
            Do not buffer multiple items if they are distinct commands. Be extremely proactive.
            Respond with brief audio confirmations like "Added" or "Got it" after capturing.
          `,
        },
        callbacks: {
          onopen: () => {
            if (mountedRef.current) {
                setIsActive(true);
                setStatusMessage("Listening...");
            }
          },
          onmessage: (msg: LiveServerMessage) => {
            if (msg.toolCall) {
              msg.toolCall.functionCalls.forEach(fc => {
                if (fc.name === 'capture_items') {
                  const args = fc.args as unknown as ProcessedInput;
                  onProcessed(args);

                  sessionPromise.then(session => {
                    session.sendToolResponse({
                      functionResponses: {
                        id: fc.id,
                        name: fc.name,
                        response: { result: "Success" }
                      }
                    });
                  });
                }
              });
            }
          },
          onclose: () => {
            if (mountedRef.current) handleSessionEnd();
          },
          onerror: (err) => {
            console.error("Live API Error", err);
            if (mountedRef.current) {
                handleSessionEnd();
                setStatusMessage("Error: Network or API Key");
            }
          }
        }
      });

      processor.onaudioprocess = (e) => {
        const inputData = e.inputBuffer.getChannelData(0);
        let sum = 0;
        for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
        if (mountedRef.current) setVolume(Math.sqrt(sum / inputData.length));

        const base64Data = encodeAudio(inputData);

        sessionPromise.then(session => {
            // Only send if session is active and we are the current session
            if (mountedRef.current && sessionRef.current === session) {
                try {
                    session.sendRealtimeInput({
                        media: {
                        mimeType: 'audio/pcm;rate=16000',
                        data: base64Data
                        }
                    });
                } catch(e) {
                    console.error("Send Error", e);
                }
            }
        }).catch(e => {
            // Swallow initial connection errors here, handled by onerror
        });
      };

      // Assign session ref immediately after promise creation (it resolves to session)
      sessionPromise.then(s => {
          sessionRef.current = s;
      });

    } catch (err) {
      console.error("Failed to start live session", err);
      handleSessionEnd();
      setStatusMessage("Mic access denied");
    }
  };

  const handleSessionEnd = () => {
      stopLiveSession();
      // Restart wake word listener after a short delay
      setTimeout(() => {
          if (recognitionRef.current && mountedRef.current && !isActive) {
              try {
                  recognitionRef.current.start();
                  setIsWakeWordListening(true);
              } catch(e) {}
          }
          if (mountedRef.current) setStatusMessage('Say "Hey Echo"');
      }, 500);
  };

  const stopLiveSession = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    if (processorRef.current) {
      processorRef.current.disconnect();
      processorRef.current = null;
    }

    setIsActive(false);
    setVolume(0);
    sessionRef.current = null;
  };

  const toggleSession = () => {
    if (isActive) {
      handleSessionEnd();
    } else {
      startLiveSession();
    }
  };

  const processTextEntry = async (text: string) => {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const now = new Date().toLocaleString();
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash", // Replaced Gemini 3
        contents: `Analyze this input for EchoFlow: "${text}". Current time: ${now}. Classify into tasks, notes, or habits. For habits, detect frequency (daily, weekly, monthly).`,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    items: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                type: { type: Type.STRING, enum: ["TASK", "NOTE", "HABIT"] },
                                content: { type: Type.STRING },
                                description: { type: Type.STRING },
                                priority: { type: Type.INTEGER },
                                dueDate: { type: Type.STRING },
                                mood: { type: Type.STRING },
                                streak: { type: Type.INTEGER },
                                frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] },
                                tags: { type: Type.ARRAY, items: { type: Type.STRING } }
                            },
                            required: ["type", "content"]
                        }
                    }
                }
            }
        }
      });
      return response.text ? JSON.parse(response.text) : null;
  };

  const handleTextSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!textInput.trim()) return;

    setIsProcessing(true);
    setStatusMessage("Processing...");
    try {
        const result = await processTextEntry(textInput);
        if (result) onProcessed(result);
        setTextInput('');
        setShowTextInput(false);
        setStatusMessage('Say "Hey Echo"');
    } catch (e) {
        console.error(e);
        setStatusMessage("Error processing text");
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <div className="fixed bottom-0 left-0 md:left-[260px] right-0 p-6 flex flex-col items-center justify-end z-20 pointer-events-none">

       {isActive && (
           <div className="pointer-events-auto mb-6 bg-zinc-900/95 backdrop-blur-xl text-white px-8 py-6 rounded-3xl shadow-2xl flex flex-col items-center gap-4 animate-in slide-in-from-bottom-10 fade-in duration-300 border border-zinc-800">
               <div className="flex items-center gap-3">
                   <div className="relative flex items-center justify-center w-4 h-4">
                       <span className="absolute w-full h-full rounded-full bg-emerald-500 animate-ping opacity-75"></span>
                       <span className="relative w-2.5 h-2.5 rounded-full bg-emerald-500"></span>
                   </div>
                   <span className="text-sm font-medium tracking-wide uppercase text-emerald-400">EchoFlow Live</span>
               </div>

               <div className="flex items-center gap-1.5 h-12 justify-center">
                   {[...Array(5)].map((_, i) => (
                       <div 
                           key={i}
                           className="w-2 bg-gradient-to-t from-emerald-500 to-emerald-300 rounded-full transition-all duration-75"
                           style={{ 
                               height: `${Math.max(15, Math.min(100, volume * 800 * (Math.random() + 0.5)))}%`,
                               opacity: 0.8 
                           }}
                       />
                   ))}
               </div>
               <p className="text-xs text-zinc-400 font-medium">Listening...</p>
           </div>
       )}

       {showTextInput && (
           <div className="pointer-events-auto w-full max-w-2xl mb-4 bg-white dark:bg-dark-surface rounded-2xl shadow-xl border border-zinc-200 dark:border-dark-border p-2 animate-in slide-in-from-bottom-5">
               <form onSubmit={handleTextSubmit} className="flex gap-2">
                   <input 
                      autoFocus
                      className="flex-1 px-4 py-3 bg-transparent outline-none text-zinc-800 dark:text-zinc-200 placeholder:text-zinc-400"
                      placeholder="Type your thought..."
                      value={textInput}
                      onChange={e => setTextInput(e.target.value)}
                      disabled={isProcessing}
                   />
                   <button 
                      type="submit" 
                      disabled={isProcessing || !textInput.trim()}
                      className="p-3 bg-brand-600 text-white rounded-xl hover:bg-brand-700 transition-colors disabled:opacity-50"
                   >
                       {isProcessing ? <Loader2 className="animate-spin" size={20}/> : <SendHorizontal size={20}/>}
                   </button>
               </form>
           </div>
       )}

      <div className="pointer-events-auto flex items-center gap-4 transition-all duration-300">
        <button 
            onClick={() => setShowTextInput(!showTextInput)}
            className="bg-white dark:bg-dark-surface text-zinc-500 dark:text-zinc-400 p-3 rounded-full shadow-lg border border-zinc-100 dark:border-dark-border hover:text-brand-600 dark:hover:text-brand-400 transition-colors"
        >
            <Keyboard size={20} />
        </button>

        <button
            onClick={toggleSession}
            className={`
            relative flex items-center justify-center w-16 h-16 rounded-full shadow-xl transition-all duration-300
            ${isActive 
                ? 'bg-zinc-800 text-emerald-400 ring-4 ring-emerald-500/20 scale-110' 
                : isProcessing 
                    ? 'bg-zinc-100 dark:bg-dark-surface text-zinc-400' 
                    : 'bg-brand-600 text-white hover:bg-brand-700 hover:scale-105 shadow-brand-500/30'
            }
            `}
        >
            {isProcessing ? (
                <Loader2 size={24} className="animate-spin" />
            ) : isActive ? (
                <Square size={20} fill="currentColor" />
            ) : (
                <div className="relative">
                    <Mic size={28} />
                    {/* Wake Word Status Indicator */}
                    {isWakeWordListening && !isActive && (
                        <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-sky-400 rounded-full border-2 border-brand-600 animate-pulse" title="Listening for 'Hey Echo'"></div>
                    )}
                </div>
            )}
        </button>
      </div>

      <div className="h-6 mt-4 text-xs font-medium text-zinc-400 dark:text-zinc-500 text-center transition-opacity duration-300 flex items-center gap-2">
        {isWakeWordListening && !isActive && <Radio size={12} className="animate-pulse text-sky-500" />}
        {statusMessage}
      </div>
    </div>
  );
};

